export enum AppointmentType {
  AVALIACAO = 'Avaliação',
  CONSULTA = 'Consulta',
  RETORNO = 'Retorno',
  ACOMPANHAMENTO = 'Acompanhamento'
}

export interface Appointment {
  id: string;
  patientId: string;
  date: string;
  type: AppointmentType;
  weight: number;
  height: number;
  notes: string;
  price: number;
}

export interface Patient {
  id: string;
  name: string;
  email: string;
  phone: string;
  birthDate: string;
  createdAt: string;
}

export enum TransactionType {
  INCOME = 'Entrada',
  EXPENSE = 'Saída'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  type: TransactionType;
  date: string;
  category: string;
}

export interface DashboardMetrics {
  totalPatients: number;
  activePatients: number; // Seen in last 60 days
  lostPatients: number; // Not seen in 60+ days
  totalRevenue: number;
  totalExpenses: number;
  netProfit: number;
  appointmentsByType: { name: string; value: number }[];
  revenueByMonth: { name: string; income: number; expense: number }[];
}

import { Patient, Appointment, Transaction, TransactionType, AppointmentType } from '../types';

// Mock Data Generators
const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_PATIENTS: Patient[] = [
  { id: 'p1', name: 'Ana Silva', email: 'ana@example.com', phone: '11999999999', birthDate: '1990-05-15', createdAt: '2023-01-10' },
  { id: 'p2', name: 'Carlos Oliveira', email: 'carlos@example.com', phone: '11988888888', birthDate: '1985-10-20', createdAt: '2023-02-15' },
  { id: 'p3', name: 'Maria Souza', email: 'maria@example.com', phone: '11977777777', birthDate: '1995-03-08', createdAt: '2023-03-01' },
];

const INITIAL_APPOINTMENTS: Appointment[] = [
  { id: 'a1', patientId: 'p1', date: '2023-10-01', type: AppointmentType.AVALIACAO, weight: 65, height: 165, notes: 'Queixa de dores lombares.', price: 200 },
  { id: 'a2', patientId: 'p1', date: '2023-10-15', type: AppointmentType.ACOMPANHAMENTO, weight: 64.5, height: 165, notes: 'Melhora parcial.', price: 150 },
  { id: 'a3', patientId: 'p2', date: '2023-10-05', type: AppointmentType.CONSULTA, weight: 80, height: 180, notes: 'Check-up geral.', price: 250 },
];

const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Aluguel Consultório', amount: 1500, type: TransactionType.EXPENSE, date: '2023-10-05', category: 'Fixo' },
  { id: 't2', description: 'Material de Escritório', amount: 200, type: TransactionType.EXPENSE, date: '2023-10-10', category: 'Variável' },
  // Income is usually generated from appointments, but adding explicit ones
  { id: 't3', description: 'Consultoria Externa', amount: 500, type: TransactionType.INCOME, date: '2023-10-12', category: 'Serviços' },
];

export const StorageService = {
  getPatients: (): Patient[] => {
    const data = localStorage.getItem('patients');
    return data ? JSON.parse(data) : INITIAL_PATIENTS;
  },

  savePatient: (patient: Patient) => {
    const patients = StorageService.getPatients();
    const index = patients.findIndex(p => p.id === patient.id);
    if (index >= 0) {
      patients[index] = patient;
    } else {
      patients.push({ ...patient, id: patient.id || generateId(), createdAt: patient.createdAt || new Date().toISOString() });
    }
    localStorage.setItem('patients', JSON.stringify(patients));
  },

  getAppointments: (): Appointment[] => {
    const data = localStorage.getItem('appointments');
    return data ? JSON.parse(data) : INITIAL_APPOINTMENTS;
  },

  saveAppointment: (appointment: Appointment) => {
    const apps = StorageService.getAppointments();
    const index = apps.findIndex(a => a.id === appointment.id);
    if (index >= 0) {
      apps[index] = appointment;
    } else {
      apps.push({ ...appointment, id: appointment.id || generateId() });
      // Automatically add income transaction
      StorageService.saveTransaction({
        id: generateId(),
        description: `${appointment.type} - ${new Date().toLocaleDateString()}`,
        amount: appointment.price,
        type: TransactionType.INCOME,
        date: appointment.date,
        category: 'Atendimentos'
      });
    }
    localStorage.setItem('appointments', JSON.stringify(apps));
  },

  getTransactions: (): Transaction[] => {
    const data = localStorage.getItem('transactions');
    return data ? JSON.parse(data) : INITIAL_TRANSACTIONS;
  },

  saveTransaction: (transaction: Transaction) => {
    const trans = StorageService.getTransactions();
    const index = trans.findIndex(t => t.id === transaction.id);
    if (index >= 0) {
      trans[index] = transaction;
    } else {
      trans.push({ ...transaction, id: transaction.id || generateId() });
    }
    localStorage.setItem('transactions', JSON.stringify(trans));
  },

  deleteTransaction: (id: string) => {
    const trans = StorageService.getTransactions().filter(t => t.id !== id);
    localStorage.setItem('transactions', JSON.stringify(trans));
  }
};

import { GoogleGenAI } from "@google/genai";
import { DashboardMetrics, Patient, Appointment } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY not found in environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const GeminiService = {
  getDashboardInsights: async (metrics: DashboardMetrics): Promise<string> => {
    const client = getAiClient();
    if (!client) return "Chave da API não configurada. Configure process.env.API_KEY para insights.";

    const prompt = `
      Atue como um consultor sênior de gestão de clínicas. Analise os seguintes dados da minha clínica e forneça 3 insights curtos e acionáveis (máximo 2 frases cada) em formato de lista Markdown. Foque em lucratividade e retenção.

      Dados:
      - Total Pacientes: ${metrics.totalPatients}
      - Pacientes Ativos (últimos 60 dias): ${metrics.activePatients}
      - Pacientes Perdidos (sem retorno > 60 dias): ${metrics.lostPatients}
      - Receita Total: R$ ${metrics.totalRevenue}
      - Lucro Líquido: R$ ${metrics.netProfit}
      - Distribuição de consultas: ${JSON.stringify(metrics.appointmentsByType)}
    `;

    try {
      const response = await client.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Não foi possível gerar insights no momento.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Erro ao conectar com a IA para análise.";
    }
  },

  getPatientSummary: async (patient: Patient, appointments: Appointment[]): Promise<string> => {
    const client = getAiClient();
    if (!client) return "Chave da API não configurada.";

    // Sort appointments by date desc
    const sortedApps = [...appointments].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const historyText = sortedApps.map(app => 
      `- ${app.date} (${app.type}): Peso ${app.weight}kg, Notas: "${app.notes}"`
    ).join('\n');

    const prompt = `
      Analise o histórico clínico deste paciente e forneça um resumo de 1 parágrafo sobre a evolução do tratamento, destacando variações de peso e frequência. Fale em português.

      Paciente: ${patient.name}, Idade: ${new Date().getFullYear() - new Date(patient.birthDate).getFullYear()} anos.
      Histórico:
      ${historyText}
    `;

    try {
      const response = await client.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Sem dados suficientes para análise.";
    } catch (error) {
      console.error(error);
      return "Erro ao analisar histórico.";
    }
  }
};

