import React, { useEffect, useState } from 'react';
import { StorageService } from '../services/storageService';
import { GeminiService } from '../services/geminiService';
import { DashboardMetrics, AppointmentType } from '../types';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Users, UserMinus, DollarSign, Wallet, Sparkles } from 'lucide-react';

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042'];

const Dashboard: React.FC = () => {
  const [metrics, setMetrics] = useState<DashboardMetrics | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    loadMetrics();
  }, []);

  const loadMetrics = () => {
    const patients = StorageService.getPatients();
    const appointments = StorageService.getAppointments();
    const transactions = StorageService.getTransactions();

    // 1. Patient Churn/Active logic
    const now = new Date();
    const sixtyDaysAgo = new Date(now.getTime() - (60 * 24 * 60 * 60 * 1000));

    let active = 0;
    let lost = 0;

    patients.forEach(p => {
      const pApps = appointments.filter(a => a.patientId === p.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      if (pApps.length === 0) {
          // New patient, technically not lost or active yet if no appt, but let's count as active for potential
          active++;
      } else {
        const lastAppDate = new Date(pApps[0].date);
        if (lastAppDate < sixtyDaysAgo) {
          lost++;
        } else {
          active++;
        }
      }
    });

    // 2. Financials
    const income = transactions.filter(t => t.type === 'Entrada').reduce((acc, curr) => acc + curr.amount, 0);
    const expense = transactions.filter(t => t.type === 'Saída').reduce((acc, curr) => acc + curr.amount, 0);

    // 3. Appointments By Type
    const typeCounts: Record<string, number> = {};
    Object.values(AppointmentType).forEach(t => typeCounts[t] = 0);
    appointments.forEach(a => {
      if (typeCounts[a.type] !== undefined) typeCounts[a.type]++;
    });
    const appsByType = Object.keys(typeCounts).map(key => ({ name: key, value: typeCounts[key] }));

    // 4. Revenue By Month (Mocking simple last 6 months for chart)
    const revenueByMonth = [
      { name: 'Mai', income: income * 0.1, expense: expense * 0.1 },
      { name: 'Jun', income: income * 0.15, expense: expense * 0.2 },
      { name: 'Jul', income: income * 0.2, expense: expense * 0.15 },
      { name: 'Ago', income: income * 0.15, expense: expense * 0.25 },
      { name: 'Set', income: income * 0.2, expense: expense * 0.15 },
      { name: 'Out', income: income * 0.2, expense: expense * 0.15 },
    ]; // Simplified for demo as calculating real monthly agg from mock data is complex without real dates.

    setMetrics({
      totalPatients: patients.length,
      activePatients: active,
      lostPatients: lost,
      totalRevenue: income,
      totalExpenses: expense,
      netProfit: income - expense,
      appointmentsByType: appsByType,
      revenueByMonth
    });
  };

  const handleGenerateInsights = async () => {
    if (!metrics) return;
    setLoadingAi(true);
    const insight = await GeminiService.getDashboardInsights(metrics);
    setAiInsight(insight);
    setLoadingAi(false);
  };

  if (!metrics) return <div>Carregando...</div>;

  return (
    <div className="space-y-6">
      {/* Top Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Pacientes</p>
            <h3 className="text-2xl font-bold text-slate-800">{metrics.totalPatients}</h3>
            <p className="text-xs text-teal-600 mt-1">{metrics.activePatients} ativos</p>
          </div>
          <div className="p-3 bg-blue-50 rounded-lg text-blue-600">
            <Users size={24} />
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
          <div>
            <p className="text-sm text-slate-500 font-medium">Pacientes em Risco</p>
            <h3 className="text-2xl font-bold text-slate-800">{metrics.lostPatients}</h3>
            <p className="text-xs text-red-500 mt-1">Ausentes &gt; 60 dias</p>
          </div>
          <div className="p-3 bg-red-50 rounded-lg text-red-600">
            <UserMinus size={24} />
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
          <div>
            <p className="text-sm text-slate-500 font-medium">Receita Total</p>
            <h3 className="text-2xl font-bold text-slate-800">R$ {metrics.totalRevenue.toFixed(2)}</h3>
          </div>
          <div className="p-3 bg-green-50 rounded-lg text-green-600">
            <DollarSign size={24} />
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
          <div>
            <p className="text-sm text-slate-500 font-medium">Lucro Líquido</p>
            <h3 className={`text-2xl font-bold ${metrics.netProfit >= 0 ? 'text-slate-800' : 'text-red-600'}`}>
              R$ {metrics.netProfit.toFixed(2)}
            </h3>
            <p className="text-xs text-slate-400 mt-1">Total</p>
          </div>
          <div className="p-3 bg-purple-50 rounded-lg text-purple-600">
            <Wallet size={24} />
          </div>
        </div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Financial Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Fluxo de Caixa (Estimado 6 Meses)</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={metrics.revenueByMonth}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.8}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#ef4444" stopOpacity={0.8}/>
                    <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" stroke="#94a3b8" />
                <YAxis stroke="#94a3b8" />
                <Tooltip />
                <Area type="monotone" dataKey="income" name="Entrada" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" />
                <Area type="monotone" dataKey="expense" name="Saída" stroke="#ef4444" fillOpacity={1} fill="url(#colorExpense)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Appointment Types */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Tipos de Atendimento</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={metrics.appointmentsByType}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {metrics.appointmentsByType.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* AI Section */}
      <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 rounded-xl shadow-lg text-white">
        <div className="flex justify-between items-start">
          <div className="flex items-center space-x-3">
             <div className="p-2 bg-white/10 rounded-full"><Sparkles className="text-yellow-400" size={20} /></div>
             <h3 className="text-lg font-bold">Inteligência Artificial ClinicFlow</h3>
          </div>
          <button 
            onClick={handleGenerateInsights}
            disabled={loadingAi}
            className="px-4 py-2 bg-teal-500 hover:bg-teal-600 text-white rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loadingAi ? 'Analisando...' : 'Gerar Análise Financeira'}
          </button>
        </div>

        {aiInsight ? (
          <div className="mt-4 p-4 bg-white/5 rounded-lg border border-white/10 prose prose-invert max-w-none">
             <div className="whitespace-pre-wrap text-sm leading-relaxed text-slate-200">
                {aiInsight}
             </div>
          </div>
        ) : (
          <p className="mt-4 text-slate-400 text-sm">
            Clique no botão para receber uma análise estratégica baseada nos seus indicadores de performance.
          </p>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

