      id: '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };
    StorageService.saveAppointment(newAppt);
    refreshData();
    setShowApptForm(false);
    // Refresh selected patient's appts logic
    setAiSummary(''); // Clear old summary as data changed
  };

  const resetForm = () => {
    setNewPatientName('');
    setNewPatientEmail('');
    setNewPatientPhone('');
    setNewPatientBirth('');
  };

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar pacientes..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => setView('new')}
            className="flex items-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors"
          >
            <Plus size={20} />
            <span>Novo Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Nome</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Contato</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Cadastro</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredPatients.map((patient) => (
                <tr key={patient.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500">
                        <User size={16} />
                      </div>
                      <span className="font-medium text-slate-700">{patient.name}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    <div className="text-sm">{patient.email}</div>
                    <div className="text-xs text-slate-400">{patient.phone}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600 text-sm">
                    {new Date(patient.createdAt).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4">
                    <button 
                      onClick={() => handleSelectPatient(patient)}
                      className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                    >
                      Ver Detalhes <ChevronRight size={16} />
                    </button>
                  </td>
                </tr>
              ))}
              {filteredPatients.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-8 text-center text-slate-500">
                    Nenhum paciente encontrado.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  // VIEW: NEW PATIENT
  if (view === 'new') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar
        </button>
        <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-8">
          <h2 className="text-2xl font-bold text-slate-800 mb-6">Cadastrar Paciente</h2>
          <form onSubmit={handleCreatePatient} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" className="w-full border p-2 rounded-lg" value={newPatientName} onChange={e => setNewPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" className="w-full border p-2 rounded-lg" value={newPatientEmail} onChange={e => setNewPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone</label>
                <input required type="tel" className="w-full border p-2 rounded-lg" value={newPatientPhone} onChange={e => setNewPatientPhone(e.target.value)} />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
              <input required type="date" className="w-full border p-2 rounded-lg" value={newPatientBirth} onChange={e => setNewPatientBirth(e.target.value)} />
            </div>
            <div className="pt-4 flex justify-end space-x-3">
              <button type="button" onClick={() => setView('list')} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg">Cancelar</button>
              <button type="submit" className="px-4 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700">Salvar Paciente</button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT DETAIL
  if (view === 'detail' && selectedPatient) {
    const patientApps = appointments
      .filter(a => a.patientId === selectedPatient.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex justify-between items-start">
           <div>
             <button onClick={() => setView('list')} className="mb-2 text-slate-500 flex items-center hover:text-slate-800 text-sm">
               <ChevronRight className="rotate-180 mr-1" size={16}/> Voltar para lista
             </button>
             <h2 className="text-3xl font-bold text-slate-800">{selectedPatient.name}</h2>
             <p className="text-slate-500">{selectedPatient.email} • {selectedPatient.phone}</p>
           </div>
           <button 
             onClick={() => setShowApptForm(true)}
             className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 flex items-center space-x-2"
           >
             <Plus size={20} /> <span>Novo Atendimento</span>
           </button>
        </div>

        {/* AI Summary Block */}
        <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl">
           <div className="flex justify-between items-center mb-2">
             <div className="flex items-center space-x-2 text-indigo-800 font-semibold">
               <Sparkles size={18} /> <span>Resumo IA do Prontuário</span>
             </div>
             <button onClick={handleGenerateSummary} disabled={loadingAi} className="text-xs text-indigo-600 hover:text-indigo-800 font-medium uppercase tracking-wide disabled:opacity-50">
               {loadingAi ? 'Gerando...' : 'Gerar Resumo'}
             </button>
           </div>
           <p className="text-sm text-indigo-900 leading-relaxed">
             {aiSummary || "Clique em 'Gerar Resumo' para que a IA analise o histórico de consultas deste paciente e forneça insights sobre a evolução."}
           </p>
        </div>

        {/* History Timeline */}
        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-700">Histórico Clínico</h3>
          {patientApps.length === 0 ? (
            <div className="bg-white p-8 rounded-xl text-center text-slate-400 border border-dashed border-slate-300">
              Nenhuma consulta registrada.
            </div>
          ) : (
            patientApps.map((app) => (
              <div key={app.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 hover:border-teal-200 transition-colors">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <span className={`inline-block px-2 py-1 rounded text-xs font-semibold mb-2
                      ${app.type === AppointmentType.AVALIACAO ? 'bg-purple-100 text-purple-700' : 
                        app.type === AppointmentType.CONSULTA ? 'bg-blue-100 text-blue-700' :
                        'bg-green-100 text-green-700'}
                    `}>
                      {app.type}
                    </span>
                    <div className="flex items-center text-slate-400 text-sm space-x-4">
                      <span className="flex items-center"><Calendar size={14} className="mr-1"/> {new Date(app.date).toLocaleDateString()}</span>
                    </div>
                  </div>
                  <div className="text-right flex items-center space-x-4">
                    <div className="flex items-center text-slate-600 text-sm">
                      <Scale size={16} className="mr-1 text-slate-400"/> <strong>{app.weight} kg</strong>
                    </div>
                    <div className="flex items-center text-slate-600 text-sm">
                      <Ruler size={16} className="mr-1 text-slate-400"/> <strong>{app.height} cm</strong>
                    </div>
                  </div>
                </div>
                <div className="bg-slate-50 p-4 rounded-lg border border-slate-100">
                  <div className="flex items-start">
                     <FileText size={16} className="mt-1 mr-2 text-slate-400 flex-shrink-0"/>
                     <p className="text-slate-700 text-sm whitespace-pre-wrap">{app.notes}</p>
                  </div>
