        {/* Modal for New Appointment */}
        {showApptForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
            <div className="bg-white rounded-xl shadow-xl max-w-lg w-full p-6 animate-fade-in">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-800">Nova Consulta</h3>
                <button onClick={() => setShowApptForm(false)} className="text-slate-400 hover:text-slate-600"><X size={24}/></button>
              </div>
              <form onSubmit={handleCreateAppointment} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase">Data</label>
                     <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border p-2 rounded mt-1" />
                   </div>
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase">Tipo</label>
                     <select value={apptType} onChange={e => setApptType(e.target.value as AppointmentType)} className="w-full border p-2 rounded mt-1">
                       {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                     </select>
                   </div>
                </div>
                <div className="grid grid-cols-3 gap-4">
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase">Peso (kg)</label>
                     <input required type="number" step="0.1" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border p-2 rounded mt-1" />
