import React, { ReactNode } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { LayoutDashboard, Users, DollarSign, Activity, Menu, X } from 'lucide-react';
import { useState } from 'react';

interface LayoutProps {
  children: ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const navItems = [
    { name: 'Dashboard', path: '/', icon: <LayoutDashboard size={20} /> },
    { name: 'Pacientes', path: '/patients', icon: <Users size={20} /> },
    { name: 'Financeiro', path: '/financials', icon: <DollarSign size={20} /> },
  ];

  const getTitle = () => {
    const item = navItems.find(i => i.path === location.pathname);
    return item ? item.name : 'ClinicFlow';
  };

  const handleNavigation = (path: string) => {
    navigate(path);
    setIsMobileOpen(false);
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 text-white shadow-xl z-20">
        <div className="p-6 flex items-center space-x-3 border-b border-slate-700">
          <Activity className="text-teal-400" />
          <span className="text-xl font-bold tracking-tight">ClinicFlow AI</span>
        </div>
        <nav className="flex-1 p-4 space-y-2">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <button
                key={item.path}
                onClick={() => handleNavigation(item.path)}
                className={`w-full flex items-center space-x-3 p-3 rounded-lg transition-colors ${
                  isActive ? 'bg-teal-600 text-white' : 'text-slate-300 hover:bg-slate-800 hover:text-white'
                }`}
              >
                {item.icon}
                <span className="font-medium">{item.name}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t border-slate-700 text-xs text-slate-500 text-center">
          v1.0.0
        </div>
      </aside>

      {/* Mobile Header & Sidebar */}
      <div className={`fixed inset-0 z-40 bg-black/50 md:hidden transition-opacity ${isMobileOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} onClick={() => setIsMobileOpen(false)} />

      <aside className={`fixed top-0 left-0 w-64 h-full bg-slate-900 text-white z-50 transform transition-transform duration-300 ease-in-out md:hidden ${isMobileOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-4 flex justify-between items-center border-b border-slate-700">
          <span className="text-xl font-bold">ClinicFlow</span>
          <button onClick={() => setIsMobileOpen(false)}><X size={24} /></button>
        </div>
        <nav className="p-4 space-y-2">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <button
                key={item.path}
                onClick={() => handleNavigation(item.path)}
                className={`w-full flex items-center space-x-3 p-3 rounded-lg ${
                  isActive ? 'bg-teal-600 text-white' : 'text-slate-300'
                }`}
              >
                {item.icon}
                <span>{item.name}</span>
              </button>
            );
          })}
        </nav>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <header className="h-16 bg-white shadow-sm flex items-center justify-between px-6 md:px-8">
          <div className="flex items-center">
             <button className="md:hidden mr-4 text-slate-600" onClick={() => setIsMobileOpen(true)}>
               <Menu size={24} />
             </button>
             <h1 className="text-2xl font-bold text-slate-800">{getTitle()}</h1>
          </div>
          <div className="flex items-center space-x-4">
             <div className="w-8 h-8 rounded-full bg-teal-100 text-teal-600 flex items-center justify-center font-bold">
               DR
             </div>
          </div>
        </header>

        <main className="flex-1 overflow-auto p-6 md:p-8">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'new'>('list');
  const [searchTerm, setSearchTerm] = useState('');

  // Form States
  const [newPatientName, setNewPatientName] = useState('');
  const [newPatientEmail, setNewPatientEmail] = useState('');
  const [newPatientPhone, setNewPatientPhone] = useState('');
  const [newPatientBirth, setNewPatientBirth] = useState('');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
  };

  const handleCreatePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const newPatient: Patient = {
      id: '', // Service handles ID
      name: newPatientName,
      email: newPatientEmail,
      phone: newPatientPhone,
      birthDate: newPatientBirth,
      createdAt: new Date().toISOString()
    };
    StorageService.savePatient(newPatient);
    refreshData();
    setView('list');
    resetForm();
  };

  const handleCreateAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;
    const newAppt: Appointment = {
      id: '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };
    StorageService.saveAppointment(newAppt);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed

    // Reset basic fields but keep weight/height for convenience? No, clearer to reset.
    setApptNotes('');
    setApptPrice('0');
  };

  const resetForm = () => {
    setNewPatientName('');
    setNewPatientEmail('');
    setNewPatientPhone('');
    setNewPatientBirth('');
  };

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patientId: string) => {
    const pApps = appointments.filter(a => a.patientId === patientId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = 'Novo';
    let statusColor = 'text-blue-500 bg-blue-50';

    if (pApps.length > 0) {
      const lastAppDate = new Date(pApps[0].date);
      const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

      if (diffDays > 60) {
        status = 'Inativo';
        statusColor = 'text-red-500 bg-red-50';
      } else {
        status = 'Ativo';
        statusColor = 'text-green-500 bg-green-50';
      }
    }

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou email..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => setView('new')}
            className="w-full md:w-auto flex items-center justify-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors shadow-sm font-medium"
          >
            <Plus size={20} />
            <span>Cadastrar Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Paciente</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Status</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Total Receita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Última Visita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((patient) => {
                  const { status, statusColor, totalSpent, lastApp } = getPatientMetrics(patient.id);
                  return (
                    <tr key={patient.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => handleSelectPatient(patient)}>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                            {patient.name.charAt(0)}
                          </div>
                          <div>
                            <span className="block font-medium text-slate-700">{patient.name}</span>
                            <span className="text-xs text-slate-400">{patient.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-medium border ${statusColor.replace('bg-', 'border-').replace('text-', 'border-opacity-20 ')} ${statusColor}`}>
                          {status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-slate-700 font-medium">
                          <TrendingUp size={14} className="mr-1 text-teal-500"/>
                          R$ {totalSpent.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-sm">
                        {lastApp ? new Date(lastApp.date).toLocaleDateString() : 'Nunca'}
                      </td>
                      <td className="px-6 py-4">
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleSelectPatient(patient); }}
                          className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                        >
                          Prontuário <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredPatients.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                      <div className="flex flex-col items-center">
                        <User size={48} className="text-slate-200 mb-2"/>
                        <p>Nenhum paciente encontrado.</p>
                        <button onClick={() => setView('new')} className="mt-2 text-teal-600 hover:underline">Cadastrar o primeiro?</button>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // VIEW: NEW PATIENT
  if (view === 'new') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar para Lista
        </button>
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
             <div className="bg-teal-100 p-2 rounded-lg text-teal-600"><User size={24}/></div>
             <div>
               <h2 className="text-xl font-bold text-slate-800">Novo Paciente</h2>
               <p className="text-sm text-slate-500">Preencha os dados básicos para iniciar o prontuário.</p>
             </div>
          </div>
          <form onSubmit={handleCreatePatient} className="p-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" placeholder="Ex: João da Silva" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={newPatientName} onChange={e => setNewPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" placeholder="joao@email.com" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={newPatientEmail} onChange={e => setNewPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone / WhatsApp</label>
                <input required type="tel" placeholder="(11) 99999-9999" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={newPatientPhone} onChange={e => setNewPatientPhone(e.target.value)} />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
              <input required type="date" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={newPatientBirth} onChange={e => setNewPatientBirth(e.target.value)} />
            </div>
            <div className="pt-6 flex justify-end space-x-3 border-t border-slate-100 mt-6">
              <button type="button" onClick={() => setView('list')} className="px-6 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
              <button type="submit" className="px-6 py-2.5 bg-teal-600 text-white rounded-lg hover:bg-teal-700 font-medium shadow-md transition-colors flex items-center">
                <CheckCircle size={18} className="mr-2"/> Salvar Cadastro
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT DETAIL
  if (view === 'detail' && selectedPatient) {
    const patientApps = appointments
      .filter(a => a.patientId === selectedPatient.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const { status, statusColor } = getPatientMetrics(selectedPatient.id);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div>
             <button onClick={() => setView('list')} className="mb-2 text-slate-500 flex items-center hover:text-slate-800 text-sm font-medium">
               <ChevronRight className="rotate-180 mr-1" size={16}/> Voltar para lista
             </button>
             <div className="flex items-center space-x-3">
               <h2 className="text-3xl font-bold text-slate-800">{selectedPatient.name}</h2>
               <span className={`px-2 py-0.5 rounded text-xs font-bold border ${statusColor.replace('bg-', 'border-')} ${statusColor}`}>{status}</span>
             </div>
             <p className="text-slate-500 mt-1 flex items-center space-x-2">
                <span>{selectedPatient.email}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span>{selectedPatient.phone}</span>
             </p>
           </div>
           <button 
             onClick={() => setShowApptForm(true)}
             className="bg-teal-600 text-white px-5 py-2.5 rounded-lg hover:bg-teal-700 flex items-center space-x-2 shadow-sm font-medium transition-all transform hover:-translate-y-0.5"
           >
             <Plus size={20} /> <span>Novo Atendimento</span>
           </button>
        </div>

        {/* AI Summary Block */}
        <div className="bg-gradient-to-r from-indigo-50 to-purple-50 border border-indigo-100 p-5 rounded-xl shadow-sm">
           <div className="flex justify-between items-center mb-3">
             <div className="flex items-center space-x-2 text-indigo-900 font-bold">
               <Sparkles size={18} className="text-purple-600" /> <span>Análise Inteligente do Prontuário</span>
             </div>
             <button onClick={handleGenerateSummary} disabled={loadingAi} className="text-xs bg-white border border-indigo-200 text-indigo-700 px-3 py-1 rounded hover:bg-indigo-50 font-medium disabled:opacity-50 transition-colors">
               {loadingAi ? 'ANALISANDO...' : 'GERAR RESUMO IA'}
             </button>
           </div>
           <p className="text-sm text-slate-700 leading-relaxed bg-white/50 p-3 rounded-lg border border-indigo-50/50">
             {aiSummary || "Clique em 'Gerar Resumo IA' para analisar a evolução do peso, frequência e notas clínicas deste paciente automaticamente."}
           </p>
        </div>

        {/* History Timeline */}
        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-700 flex items-center"><FileText size={20} className="mr-2 text-slate-400"/> Histórico de Consultas</h3>
          {patientApps.length === 0 ? (
            <div className="bg-white p-12 rounded-xl text-center border-2 border-dashed border-slate-200">
              <div className="mx-auto w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-3">
                <Calendar size={32} />
              </div>
              <h4 className="text-slate-500 font-medium">Nenhum atendimento registrado</h4>
              <p className="text-slate-400 text-sm mt-1">Clique em "Novo Atendimento" para iniciar.</p>
            </div>
          ) : (
            patientApps.map((app) => (
              <div key={app.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow">
                <div className="p-5">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-4">
                    <div className="flex items-center space-x-3">
                       <div className={`p-2 rounded-lg ${
                         app.type === AppointmentType.AVALIACAO ? 'bg-purple-100 text-purple-700' : 
                         app.type === AppointmentType.CONSULTA ? 'bg-blue-100 text-blue-700' :
                         'bg-green-100 text-green-700'
                       }`}>
                         <Calendar size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-slate-800 text-lg">{app.type}</h4>
                         <p className="text-slate-500 text-sm">{new Date(app.date).toLocaleDateString()} • {new Date(app.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                       </div>
                    </div>
                    <div className="flex items-center space-x-6 bg-slate-50 px-4 py-2 rounded-lg border border-slate-100">
                      <div className="text-center">
                        <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Peso</span>
                        <span className="font-bold text-slate-700 flex items-center"><Scale size={14} className="mr-1 text-slate-400"/> {app.weight} kg</span>
                      </div>
                      <div className="w-px h-8 bg-slate-200"></div>
                      <div className="text-center">
                        <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Altura</span>
                        <span className="font-bold text-slate-700 flex items-center"><Ruler size={14} className="mr-1 text-slate-400"/> {app.height} cm</span>
                      </div>
                    </div>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 text-slate-700 text-sm leading-relaxed">
                    <span className="font-semibold text-slate-900 block mb-1">Anotações Clínicas:</span>
                    {app.notes}
                  </div>
                  <div className="mt-3 text-right">
                     <span className="text-xs text-slate-400 font-medium">Valor da Consulta: </span>
                     <span className="text-sm font-bold text-teal-600">R$ {app.price.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Modal for New Appointment */}
        {showApptForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-lg font-bold text-slate-800 flex items-center"><Plus size={18} className="mr-2 text-teal-600"/> Registrar Atendimento</h3>
                <button onClick={() => setShowApptForm(false)} className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-1 rounded-full border border-slate-200 hover:bg-slate-100"><X size={20}/></button>
              </div>
              <div className="p-6 overflow-y-auto">
                <form onSubmit={handleCreateAppointment} className="space-y-5">
                  <div className="grid grid-cols-2 gap-5">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data do Atendimento</label>
                       <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                       <select value={apptType} onChange={e => setApptType(e.target.value as AppointmentType)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white">
                         {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                       </select>
                     </div>
                  </div>

                  <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 grid grid-cols-3 gap-4">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                       <div className="relative">
                         <input required type="number" step="0.1" placeholder="0.0" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border border-slate-300 p-2 pl-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                       </div>
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                       <input required type="number" placeholder="0" value={apptHeight} onChange={e => setApptHeight(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                       <input required type="number" placeholder="0.00" value={apptPrice} onChange={e => setApptPrice(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                  </div>

                  <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Descrição / Evolução Clínica</label>
                     <textarea required rows={5} placeholder="Descreva os detalhes da consulta, queixas e observações..." value={apptNotes} onChange={e => setApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none"></textarea>
                  </div>

                  <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                    <CheckCircle size={20} className="mr-2" /> Salvar Atendimento
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
};

