import React from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Patients from './pages/Patients';
import Financials from './pages/Financials';

const App: React.FC = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/patients" element={<Patients />} />
          <Route path="/financials" element={<Financials />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

import React from 'react';
import { MemoryRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Patients from './pages/Patients';
import Financials from './pages/Financials';

const App: React.FC = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/patients" element={<Patients />} />
          <Route path="/financials" element={<Financials />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp, Edit2 } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'form'>('list'); // Renamed 'new' to 'form'
  const [searchTerm, setSearchTerm] = useState('');

  // Patient Form States
  const [editingPatientId, setEditingPatientId] = useState<string | null>(null);
  const [patientName, setPatientName] = useState('');
  const [patientEmail, setPatientEmail] = useState('');
  const [patientPhone, setPatientPhone] = useState('');
  const [patientBirth, setPatientBirth] = useState('');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [editingApptId, setEditingApptId] = useState<string | null>(null);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
  };

  // --- PATIENT ACTIONS ---

  const handleSavePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const patientData: Patient = {
      id: editingPatientId || '', // Empty ID triggers creation in StorageService, ID triggers update
      name: patientName,
      email: patientEmail,
      phone: patientPhone,
      birthDate: patientBirth,
      createdAt: editingPatientId && selectedPatient ? selectedPatient.createdAt : new Date().toISOString()
    };

    StorageService.savePatient(patientData);

    // If editing active patient, update the selected view
    if (selectedPatient && editingPatientId === selectedPatient.id) {
        setSelectedPatient(patientData);
    }

    refreshData();
    setView('list');
    resetPatientForm();
  };

  const startNewPatient = () => {
    resetPatientForm();
    setView('form');
  };

  const startEditPatient = (patient: Patient) => {
    setEditingPatientId(patient.id);
    setPatientName(patient.name);
    setPatientEmail(patient.email);
    setPatientPhone(patient.phone);
    setPatientBirth(patient.birthDate);
    setView('form');
  };

  const resetPatientForm = () => {
    setEditingPatientId(null);
    setPatientName('');
    setPatientEmail('');
    setPatientPhone('');
    setPatientBirth('');
  };

  // --- APPOINTMENT ACTIONS ---

  const handleSaveAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;

    const apptData: Appointment = {
      id: editingApptId || '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };

    StorageService.saveAppointment(apptData);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed
    resetApptForm();
  };

  const startNewAppointment = () => {
    resetApptForm();
    setShowApptForm(true);
  };

  const startEditAppointment = (app: Appointment) => {
    setEditingApptId(app.id);
    setApptDate(app.date);
    setApptType(app.type);
    setApptWeight(app.weight.toString());
    setApptHeight(app.height.toString());
    setApptNotes(app.notes);
    setApptPrice(app.price.toString());
    setShowApptForm(true);
  };

  const resetApptForm = () => {
    setEditingApptId(null);
    setApptDate(new Date().toISOString().split('T')[0]);
    setApptType(AppointmentType.CONSULTA);
    setApptWeight('');
    setApptHeight('');
    setApptNotes('');
    setApptPrice('0');
  };

  // --- VIEW LOGIC ---

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patientId: string) => {
    const pApps = appointments.filter(a => a.patientId === patientId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = 'Novo';
    let statusColor = 'text-blue-500 bg-blue-50';

    if (pApps.length > 0) {
      const lastAppDate = new Date(pApps[0].date);
      const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

      if (diffDays > 60) {
        status = 'Inativo';
        statusColor = 'text-red-500 bg-red-50';
      } else {
        status = 'Ativo';
        statusColor = 'text-green-500 bg-green-50';
      }
    }

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou email..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={startNewPatient}
            className="w-full md:w-auto flex items-center justify-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors shadow-sm font-medium"
          >
            <Plus size={20} />
            <span>Cadastrar Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Paciente</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Status</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Total Receita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Última Visita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((patient) => {
                  const { status, statusColor, totalSpent, lastApp } = getPatientMetrics(patient.id);
                  return (
                    <tr key={patient.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => handleSelectPatient(patient)}>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                            {patient.name.charAt(0)}
                          </div>
                          <div>
                            <span className="block font-medium text-slate-700">{patient.name}</span>
                            <span className="text-xs text-slate-400">{patient.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-medium border ${statusColor.replace('bg-', 'border-').replace('text-', 'border-opacity-20 ')} ${statusColor}`}>
                          {status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-slate-700 font-medium">
                          <TrendingUp size={14} className="mr-1 text-teal-500"/>
                          R$ {totalSpent.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-sm">
                        {lastApp ? new Date(lastApp.date).toLocaleDateString() : 'Nunca'}
                      </td>
                      <td className="px-6 py-4">
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleSelectPatient(patient); }}
                          className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                        >
                          Prontuário <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredPatients.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                      <div className="flex flex-col items-center">
                        <User size={48} className="text-slate-200 mb-2"/>
                        <p>Nenhum paciente encontrado.</p>
                        <button onClick={startNewPatient} className="mt-2 text-teal-600 hover:underline">Cadastrar o primeiro?</button>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT FORM (NEW OR EDIT)
  if (view === 'form') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar para Lista
        </button>
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
             <div className="bg-teal-100 p-2 rounded-lg text-teal-600"><User size={24}/></div>
             <div>
               <h2 className="text-xl font-bold text-slate-800">{editingPatientId ? 'Editar Paciente' : 'Novo Paciente'}</h2>
               <p className="text-sm text-slate-500">{editingPatientId ? 'Atualize os dados abaixo.' : 'Preencha os dados básicos para iniciar o prontuário.'}</p>
             </div>
          </div>
          <form onSubmit={handleSavePatient} className="p-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" placeholder="Ex: João da Silva" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientName} onChange={e => setPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" placeholder="joao@email.com" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientEmail} onChange={e => setPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone / WhatsApp</label>
                <input required type="tel" placeholder="(11) 99999-9999" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientPhone} onChange={e => setPatientPhone(e.target.value)} />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
              <input required type="date" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientBirth} onChange={e => setPatientBirth(e.target.value)} />
            </div>
            <div className="pt-6 flex justify-end space-x-3 border-t border-slate-100 mt-6">
              <button type="button" onClick={() => setView('list')} className="px-6 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
              <button type="submit" className="px-6 py-2.5 bg-teal-600 text-white rounded-lg hover:bg-teal-700 font-medium shadow-md transition-colors flex items-center">
                <CheckCircle size={18} className="mr-2"/> {editingPatientId ? 'Atualizar Dados' : 'Salvar Cadastro'}
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT DETAIL
  if (view === 'detail' && selectedPatient) {
    const patientApps = appointments
      .filter(a => a.patientId === selectedPatient.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const { status, statusColor } = getPatientMetrics(selectedPatient.id);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div className="w-full md:w-auto">
             <button onClick={() => setView('list')} className="mb-2 text-slate-500 flex items-center hover:text-slate-800 text-sm font-medium">
               <ChevronRight className="rotate-180 mr-1" size={16}/> Voltar para lista
             </button>
             <div className="flex items-center space-x-3">
               <h2 className="text-3xl font-bold text-slate-800">{selectedPatient.name}</h2>
               <span className={`px-2 py-0.5 rounded text-xs font-bold border ${statusColor.replace('bg-', 'border-')} ${statusColor}`}>{status}</span>
               <button onClick={() => startEditPatient(selectedPatient)} className="text-slate-400 hover:text-teal-600 transition-colors p-1 rounded hover:bg-slate-100">
                 <Edit2 size={18} />
               </button>
             </div>
             <p className="text-slate-500 mt-1 flex items-center space-x-2">
                <span>{selectedPatient.email}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span>{selectedPatient.phone}</span>
             </p>
           </div>
           <button 
             onClick={startNewAppointment}
             className="bg-teal-600 text-white px-5 py-2.5 rounded-lg hover:bg-teal-700 flex items-center space-x-2 shadow-sm font-medium transition-all transform hover:-translate-y-0.5"
           >
             <Plus size={20} /> <span>Novo Atendimento</span>
           </button>
        </div>

        {/* AI Summary Block */}
        <div className="bg-gradient-to-r from-indigo-50 to-purple-50 border border-indigo-100 p-5 rounded-xl shadow-sm">
           <div className="flex justify-between items-center mb-3">
             <div className="flex items-center space-x-2 text-indigo-900 font-bold">
               <Sparkles size={18} className="text-purple-600" /> <span>Análise Inteligente do Prontuário</span>
             </div>
             <button onClick={handleGenerateSummary} disabled={loadingAi} className="text-xs bg-white border border-indigo-200 text-indigo-700 px-3 py-1 rounded hover:bg-indigo-50 font-medium disabled:opacity-50 transition-colors">
               {loadingAi ? 'ANALISANDO...' : 'GERAR RESUMO IA'}
             </button>
           </div>
           <p className="text-sm text-slate-700 leading-relaxed bg-white/50 p-3 rounded-lg border border-indigo-50/50">
             {aiSummary || "Clique em 'Gerar Resumo IA' para analisar a evolução do peso, frequência e notas clínicas deste paciente automaticamente."}
           </p>
        </div>

        {/* History Timeline */}
        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-700 flex items-center"><FileText size={20} className="mr-2 text-slate-400"/> Histórico de Consultas</h3>
          {patientApps.length === 0 ? (
            <div className="bg-white p-12 rounded-xl text-center border-2 border-dashed border-slate-200">
              <div className="mx-auto w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-3">
                <Calendar size={32} />
              </div>
              <h4 className="text-slate-500 font-medium">Nenhum atendimento registrado</h4>
              <p className="text-slate-400 text-sm mt-1">Clique em "Novo Atendimento" para iniciar.</p>
            </div>
          ) : (
            patientApps.map((app) => (
              <div key={app.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow group">
                <div className="p-5">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-4">
                    <div className="flex items-center space-x-3">
                       <div className={`p-2 rounded-lg ${
                         app.type === AppointmentType.AVALIACAO ? 'bg-purple-100 text-purple-700' : 
                         app.type === AppointmentType.CONSULTA ? 'bg-blue-100 text-blue-700' :
                         'bg-green-100 text-green-700'
                       }`}>
                         <Calendar size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-slate-800 text-lg">{app.type}</h4>
                         <p className="text-slate-500 text-sm">{new Date(app.date).toLocaleDateString()} • {new Date(app.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                       </div>
                    </div>
                    <div className="flex items-center space-x-4">
                        <div className="flex items-center space-x-6 bg-slate-50 px-4 py-2 rounded-lg border border-slate-100">
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Peso</span>
                            <span className="font-bold text-slate-700 flex items-center"><Scale size={14} className="mr-1 text-slate-400"/> {app.weight} kg</span>
                        </div>
                        <div className="w-px h-8 bg-slate-200"></div>
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Altura</span>
                            <span className="font-bold text-slate-700 flex items-center"><Ruler size={14} className="mr-1 text-slate-400"/> {app.height} cm</span>
                        </div>
                        </div>
                        <button onClick={() => startEditAppointment(app)} className="text-slate-300 hover:text-teal-600 transition-colors p-2 hover:bg-slate-50 rounded-full">
                            <Edit2 size={18} />
                        </button>
                    </div>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 text-slate-700 text-sm leading-relaxed">
                    <span className="font-semibold text-slate-900 block mb-1">Anotações Clínicas:</span>
                    {app.notes}
                  </div>
                  <div className="mt-3 text-right">
                     <span className="text-xs text-slate-400 font-medium">Valor da Consulta: </span>
                     <span className="text-sm font-bold text-teal-600">R$ {app.price.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Modal for Appointment (New/Edit) */}
        {showApptForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-lg font-bold text-slate-800 flex items-center">
                    {editingApptId ? <Edit2 size={18} className="mr-2 text-teal-600"/> : <Plus size={18} className="mr-2 text-teal-600"/>} 
                    {editingApptId ? 'Editar Atendimento' : 'Registrar Atendimento'}
                </h3>
                <button onClick={() => setShowApptForm(false)} className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-1 rounded-full border border-slate-200 hover:bg-slate-100"><X size={20}/></button>
              </div>
              <div className="p-6 overflow-y-auto">
                <form onSubmit={handleSaveAppointment} className="space-y-5">
                  <div className="grid grid-cols-2 gap-5">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data do Atendimento</label>
                       <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                       <select value={apptType} onChange={e => setApptType(e.target.value as AppointmentType)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white">
                         {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                       </select>
                     </div>
                  </div>

                  <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 grid grid-cols-3 gap-4">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                       <div className="relative">
                         <input required type="number" step="0.1" placeholder="0.0" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border border-slate-300 p-2 pl-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                       </div>
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                       <input required type="number" placeholder="0" value={apptHeight} onChange={e => setApptHeight(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                       <input required type="number" placeholder="0.00" value={apptPrice} onChange={e => setApptPrice(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                  </div>

                  <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Descrição / Evolução Clínica</label>
                     <textarea required rows={5} placeholder="Descreva os detalhes da consulta, queixas e observações..." value={apptNotes} onChange={e => setApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none"></textarea>
                  </div>

                  <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                    <CheckCircle size={20} className="mr-2" /> {editingApptId ? 'Atualizar Atendimento' : 'Salvar Atendimento'}
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
};

export default Patients;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Transaction, TransactionType } from '../types';
import { Plus, Trash2, TrendingUp, TrendingDown, ArrowUpRight, ArrowDownRight, Edit2 } from 'lucide-react';

const Financials: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [desc, setDesc] = useState('');
  const [amount, setAmount] = useState('');
  const [type, setType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [category, setCategory] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    const t = StorageService.getTransactions();
    // Sort by date desc
    t.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setTransactions(t);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const newT: Transaction = {
      id: editingId || '', // If ID exists, StorageService updates; if empty, it creates.
      description: desc,
      amount: Number(amount),
      type,
      date,
      category
    };
    StorageService.saveTransaction(newT);
    setShowModal(false);
    resetForm();
    loadData();
  };

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setDesc(t.description);
    setAmount(t.amount.toString());
    setType(t.type);
    setDate(t.date);
    setCategory(t.category);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if(confirm('Tem certeza que deseja remover este lançamento?')) {
      StorageService.deleteTransaction(id);
      loadData();
    }
  };

  const startNew = () => {
    resetForm();
    setShowModal(true);
  };

  const resetForm = () => {
    setEditingId(null);
    setDesc('');
    setAmount('');
    setType(TransactionType.EXPENSE);
    setCategory('');
    setDate(new Date().toISOString().split('T')[0]);
  };

  const totalIncome = transactions.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
  const balance = totalIncome - totalExpense;

  return (
    <div className="space-y-6">
      {/* Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
           <div className="flex items-center space-x-3 mb-2">
             <div className="p-2 bg-green-100 rounded-lg text-green-600"><TrendingUp size={20}/></div>
             <span className="text-slate-500 font-medium">Entradas</span>
           </div>
           <h3 className="text-2xl font-bold text-slate-800">R$ {totalIncome.toFixed(2)}</h3>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
           <div className="flex items-center space-x-3 mb-2">
             <div className="p-2 bg-red-100 rounded-lg text-red-600"><TrendingDown size={20}/></div>
             <span className="text-slate-500 font-medium">Despesas</span>
           </div>
           <h3 className="text-2xl font-bold text-slate-800">R$ {totalExpense.toFixed(2)}</h3>
        </div>
        <div className="bg-slate-800 p-6 rounded-xl shadow-lg text-white">
           <div className="flex items-center space-x-3 mb-2">
             <div className="p-2 bg-white/10 rounded-lg text-teal-400"><TrendingUp size={20}/></div>
             <span className="text-slate-300 font-medium">Saldo Atual</span>
           </div>
           <h3 className="text-2xl font-bold">R$ {balance.toFixed(2)}</h3>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-slate-100">
        <h2 className="text-lg font-bold text-slate-700">Lançamentos</h2>
        <button 
          onClick={startNew}
          className="bg-slate-900 text-white px-4 py-2 rounded-lg hover:bg-slate-800 flex items-center space-x-2 text-sm font-medium"
        >
          <Plus size={18} /> <span>Novo Lançamento</span>
        </button>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Data</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Descrição</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Categoria</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase text-right">Valor</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.map(t => (
              <tr key={t.id} className="hover:bg-slate-50">
                 <td className="px-6 py-4 text-slate-600 text-sm">{new Date(t.date).toLocaleDateString()}</td>
                 <td className="px-6 py-4 font-medium text-slate-700">{t.description}</td>
                 <td className="px-6 py-4 text-slate-500 text-sm">{t.category}</td>
                 <td className="px-6 py-4 text-right font-bold text-sm">
                   <span className={t.type === TransactionType.INCOME ? 'text-green-600 flex items-center justify-end' : 'text-red-600 flex items-center justify-end'}>
                     {t.type === TransactionType.INCOME ? <ArrowUpRight size={14} className="mr-1"/> : <ArrowDownRight size={14} className="mr-1"/>}
                     R$ {t.amount.toFixed(2)}
                   </span>
                 </td>
                 <td className="px-6 py-4 text-center">
                   <div className="flex items-center justify-center space-x-2">
                     <button onClick={() => handleEdit(t)} className="text-slate-400 hover:text-teal-600 transition-colors">
                       <Edit2 size={18} />
                     </button>
                     <button onClick={() => handleDelete(t.id)} className="text-slate-400 hover:text-red-500 transition-colors">
                       <Trash2 size={18} />
                     </button>
                   </div>
                 </td>
              </tr>
            ))}
            {transactions.length === 0 && (
              <tr><td colSpan={5} className="p-8 text-center text-slate-400">Nenhum lançamento registrado.</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md p-6">
            <h3 className="text-xl font-bold text-slate-800 mb-4">{editingId ? 'Editar Movimentação' : 'Adicionar Movimentação'}</h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                 <div>
                   <label className="text-xs font-bold text-slate-500 uppercase">Tipo</label>
                   <select value={type} onChange={e => setType(e.target.value as TransactionType)} className="w-full border p-2 rounded mt-1">
                     <option value={TransactionType.INCOME}>Entrada</option>
                     <option value={TransactionType.EXPENSE}>Saída</option>
                   </select>
                 </div>
                 <div>
                   <label className="text-xs font-bold text-slate-500 uppercase">Valor</label>
                   <input required type="number" step="0.01" value={amount} onChange={e => setAmount(e.target.value)} className="w-full border p-2 rounded mt-1" />
                 </div>
              </div>
              <div>
                 <label className="text-xs font-bold text-slate-500 uppercase">Descrição</label>
                 <input required type="text" value={desc} onChange={e => setDesc(e.target.value)} className="w-full border p-2 rounded mt-1" placeholder="Ex: Pagamento Consulta" />
              </div>
              <div>
                 <label className="text-xs font-bold text-slate-500 uppercase">Categoria</label>
                 <input required type="text" value={category} onChange={e => setCategory(e.target.value)} className="w-full border p-2 rounded mt-1" placeholder="Ex: Fixo, Variável, Serviços" />
              </div>
              <div>
                 <label className="text-xs font-bold text-slate-500 uppercase">Data</label>
                 <input required type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full border p-2 rounded mt-1" />
              </div>
              <div className="pt-2 flex space-x-3">
                 <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-2 text-slate-600 bg-slate-100 rounded-lg hover:bg-slate-200">Cancelar</button>
                 <button type="submit" className="flex-1 py-2 text-white bg-slate-900 rounded-lg hover:bg-slate-800">{editingId ? 'Atualizar' : 'Salvar'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Financials;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp, Edit2, ChevronDown } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'form'>('list'); // Renamed 'new' to 'form'
  const [searchTerm, setSearchTerm] = useState('');

  // Patient Form States
  const [editingPatientId, setEditingPatientId] = useState<string | null>(null);
  const [patientName, setPatientName] = useState('');
  const [patientEmail, setPatientEmail] = useState('');
  const [patientPhone, setPatientPhone] = useState('');
  const [patientBirth, setPatientBirth] = useState('');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [editingApptId, setEditingApptId] = useState<string | null>(null);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
  };

  // --- PATIENT ACTIONS ---

  const handleSavePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const patientData: Patient = {
      id: editingPatientId || '', // Empty ID triggers creation in StorageService, ID triggers update
      name: patientName,
      email: patientEmail,
      phone: patientPhone,
      birthDate: patientBirth,
      createdAt: editingPatientId && selectedPatient ? selectedPatient.createdAt : new Date().toISOString()
    };

    StorageService.savePatient(patientData);

    // If editing active patient, update the selected view
    if (selectedPatient && editingPatientId === selectedPatient.id) {
        setSelectedPatient(patientData);
    }

    refreshData();
    setView('list');
    resetPatientForm();
  };

  const startNewPatient = () => {
    resetPatientForm();
    setView('form');
  };

  const startEditPatient = (patient: Patient) => {
    setEditingPatientId(patient.id);
    setPatientName(patient.name);
    setPatientEmail(patient.email);
    setPatientPhone(patient.phone);
    setPatientBirth(patient.birthDate);
    setView('form');
  };

  const resetPatientForm = () => {
    setEditingPatientId(null);
    setPatientName('');
    setPatientEmail('');
    setPatientPhone('');
    setPatientBirth('');
  };

  // --- APPOINTMENT ACTIONS ---

  const handleSaveAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;

    const apptData: Appointment = {
      id: editingApptId || '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };

    StorageService.saveAppointment(apptData);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed
    resetApptForm();
  };

  const startNewAppointment = () => {
    resetApptForm();
    setShowApptForm(true);
  };

  const startEditAppointment = (app: Appointment) => {
    setEditingApptId(app.id);
    setApptDate(app.date);
    setApptType(app.type);
    setApptWeight(app.weight.toString());
    setApptHeight(app.height.toString());
    setApptNotes(app.notes);
    setApptPrice(app.price.toString());
    setShowApptForm(true);
  };

  const resetApptForm = () => {
    setEditingApptId(null);
    setApptDate(new Date().toISOString().split('T')[0]);
    setApptType(AppointmentType.CONSULTA);
    setApptWeight('');
    setApptHeight('');
    setApptNotes('');
    setApptPrice('0');
  };

  // --- VIEW LOGIC ---

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patientId: string) => {
    const pApps = appointments.filter(a => a.patientId === patientId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = 'Novo';
    let statusColor = 'text-blue-500 bg-blue-50';

    if (pApps.length > 0) {
      const lastAppDate = new Date(pApps[0].date);
      const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

      if (diffDays > 60) {
        status = 'Inativo';
        statusColor = 'text-red-500 bg-red-50';
      } else {
        status = 'Ativo';
        statusColor = 'text-green-500 bg-green-50';
      }
    }

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou email..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={startNewPatient}
            className="w-full md:w-auto flex items-center justify-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors shadow-sm font-medium"
          >
            <Plus size={20} />
            <span>Cadastrar Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Paciente</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Status</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Total Receita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Última Visita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((patient) => {
                  const { status, statusColor, totalSpent, lastApp } = getPatientMetrics(patient.id);
                  return (
                    <tr key={patient.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => handleSelectPatient(patient)}>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                            {patient.name.charAt(0)}
                          </div>
                          <div>
                            <span className="block font-medium text-slate-700">{patient.name}</span>
                            <span className="text-xs text-slate-400">{patient.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-medium border ${statusColor.replace('bg-', 'border-').replace('text-', 'border-opacity-20 ')} ${statusColor}`}>
                          {status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-slate-700 font-medium">
                          <TrendingUp size={14} className="mr-1 text-teal-500"/>
                          R$ {totalSpent.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-sm">
                        {lastApp ? new Date(lastApp.date).toLocaleDateString() : 'Nunca'}
                      </td>
                      <td className="px-6 py-4">
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleSelectPatient(patient); }}
                          className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                        >
                          Prontuário <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredPatients.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                      <div className="flex flex-col items-center">
                        <User size={48} className="text-slate-200 mb-2"/>
                        <p>Nenhum paciente encontrado.</p>
                        <button onClick={startNewPatient} className="mt-2 text-teal-600 hover:underline">Cadastrar o primeiro?</button>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT FORM (NEW OR EDIT)
  if (view === 'form') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar para Lista
        </button>
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
             <div className="bg-teal-100 p-2 rounded-lg text-teal-600"><User size={24}/></div>
             <div>
               <h2 className="text-xl font-bold text-slate-800">{editingPatientId ? 'Editar Paciente' : 'Novo Paciente'}</h2>
               <p className="text-sm text-slate-500">{editingPatientId ? 'Atualize os dados abaixo.' : 'Preencha os dados básicos para iniciar o prontuário.'}</p>
             </div>
          </div>
          <form onSubmit={handleSavePatient} className="p-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" placeholder="Ex: João da Silva" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientName} onChange={e => setPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" placeholder="joao@email.com" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientEmail} onChange={e => setPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone / WhatsApp</label>
                <input required type="tel" placeholder="(11) 99999-9999" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientPhone} onChange={e => setPatientPhone(e.target.value)} />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
              <input required type="date" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientBirth} onChange={e => setPatientBirth(e.target.value)} />
            </div>
            <div className="pt-6 flex justify-end space-x-3 border-t border-slate-100 mt-6">
              <button type="button" onClick={() => setView('list')} className="px-6 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
              <button type="submit" className="px-6 py-2.5 bg-teal-600 text-white rounded-lg hover:bg-teal-700 font-medium shadow-md transition-colors flex items-center">
                <CheckCircle size={18} className="mr-2"/> {editingPatientId ? 'Atualizar Dados' : 'Salvar Cadastro'}
              </button>
            </div>
