```xml
<change>
    <file>pages/Patients.tsx</file>
    <content><![CDATA[import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import { useSession } from 'next-auth/react';
import { Patient, UpdatePatientData } from '../../types/patient';
import { getPatient, updatePatient, createPatient } from '../../services/patientService';
import { usePatientContext } from '../../context/PatientContext';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import ChevronDown from '../../components/ChevronDown';
import LoadingSpinner from '../../components/LoadingSpinner';

const EditPatient = () => {
    const router = useRouter();
    const { id } = router.query;
    const { data: session, status } = useSession();
    const { setSelectedPatient, selectedPatient } = usePatientContext();
    const [patient, setPatient] = useState<Patient | null>(null);
    const [patientName, setPatientName] = useState('');
    const [patientEmail, setPatientEmail] = useState('');
    const [patientPhone, setPatientPhone] = useState('');
    const [patientStatus, setPatientStatus] = useState('Ativo');
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchPatient = async () => {
            if (id && typeof id === 'string' && session?.user?.accessToken) {
                try {
                    const fetchedPatient = await getPatient(id, session.user.accessToken);
                    setPatient(fetchedPatient);
                    setPatientName(fetchedPatient.name);
                    setPatientEmail(fetchedPatient.email);
                    setPatientPhone(fetchedPatient.phone);
                    setPatientStatus(fetchedPatient.status);
                    setSelectedPatient(fetchedPatient);
                } catch (error) {
                    console.error('Error fetching patient:', error);
                    toast.error('Failed to load patient data.');
                } finally {
                    setIsLoading(false);
                }
            } else {
                setIsLoading(false);
            }
        };

        fetchPatient();
    }, [id, session?.user?.accessToken, setSelectedPatient]);

    useEffect(() => {
        if (selectedPatient) {
            setPatientName(selectedPatient.name);
            setPatientEmail(selectedPatient.email);
            setPatientPhone(selectedPatient.phone);
            setPatientStatus(selectedPatient.status);
        }
    }, [selectedPatient]);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        switch (name) {
            case 'name':
                setPatientName(value);
                break;
            case 'email':
                setPatientEmail(value);
                break;
            case 'phone':
                setPatientPhone(value);
                break;
            case 'status':
                setPatientStatus(value);
                break;
            default:
                break;
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!session?.user?.accessToken) {
            toast.error('Not authenticated.');
            return;
        }

        if (!patient || !id) {
            toast.error('Patient data is missing.');
            return;
        }

        const updateData: UpdatePatientData = {
            name: patientName,
            email: patientEmail,
            phone: patientPhone,
            status: patientStatus,
        };

        try {
            await updatePatient(id as string, updateData, session.user.accessToken);
            toast.success('Patient updated successfully!');
            router.push('/patients');
        } catch (error) {
            console.error('Failed to update patient:', error);
            toast.error('Failed to update patient. Please try again.');
