import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Service, Professional } from '../types';
import { Plus, Edit2, Trash2, Clock, DollarSign, User, Mail, Phone, BadgeCheck, AlertCircle } from 'lucide-react';

const Services: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'services' | 'professionals'>('services');
  const [services, setServices] = useState<Service[]>([]);
  const [professionals, setProfessionals] = useState<Professional[]>([]);

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);

  // Form States
  const [editingId, setEditingId] = useState<string | null>(null);

  // Service Form Fields
  const [serviceName, setServiceName] = useState('');
  const [serviceDesc, setServiceDesc] = useState('');
  const [servicePrice, setServicePrice] = useState('');
  const [serviceDuration, setServiceDuration] = useState('');

  // Professional Form Fields
  const [profName, setProfName] = useState('');
  const [profSpecialty, setProfSpecialty] = useState('');
  const [profEmail, setProfEmail] = useState('');
  const [profPhone, setProfPhone] = useState('');
  const [profReg, setProfReg] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setServices(StorageService.getServices());
    setProfessionals(StorageService.getProfessionals());
  };

  const openModal = (item?: Service | Professional) => {
    setEditingId(item ? item.id : null);
    if (activeTab === 'services') {
      const s = item as Service;
      setServiceName(s ? s.name : '');
      setServiceDesc(s ? s.description : '');
      setServicePrice(s ? s.price.toString() : '');
      setServiceDuration(s ? s.duration.toString() : '');
    } else {
      const p = item as Professional;
      setProfName(p ? p.name : '');
      setProfSpecialty(p ? p.specialty : '');
      setProfEmail(p ? p.email : '');
      setProfPhone(p ? p.phone : '');
      setProfReg(p ? p.registrationNumber : '');
    }
    setShowModal(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'services') {
      const newService: Service = {
        id: editingId || '',
        name: serviceName,
        description: serviceDesc,
        price: Number(servicePrice),
        duration: Number(serviceDuration)
      };
      StorageService.saveService(newService);
    } else {
      const newProf: Professional = {
        id: editingId || '',
        name: profName,
        specialty: profSpecialty,
        email: profEmail,
        phone: profPhone,
        registrationNumber: profReg
      };
      StorageService.saveProfessional(newProf);
    }
    setShowModal(false);
    loadData();
  };

  const handleDeleteClick = (id: string) => {
    setItemToDelete(id);
    setShowDeleteModal(true);
  };

  const confirmDelete = () => {
    if (itemToDelete) {
      if (activeTab === 'services') {
        StorageService.deleteService(itemToDelete);
      } else {
        StorageService.deleteProfessional(itemToDelete);
      }
      loadData();
      setShowDeleteModal(false);
      setItemToDelete(null);
    }
  };

  return (
    <div className="space-y-6">
      {/* Header & Tabs */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800">Serviços e Profissionais</h2>
           <p className="text-slate-500 text-sm">Gerencie os tratamentos oferecidos e a equipe da clínica.</p>
        </div>
        <div className="bg-slate-100 p-1 rounded-lg flex space-x-1">
          <button 
            onClick={() => setActiveTab('services')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'services' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Serviços & Valores
          </button>
          <button 
            onClick={() => setActiveTab('professionals')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'professionals' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Profissionais
          </button>
        </div>
      </div>

      <div className="flex justify-end">
        <button 
          onClick={() => openModal()}
          className="bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 flex items-center space-x-2 font-medium shadow-sm transition-transform active:scale-95"
        >
          <Plus size={20} />
          <span>{activeTab === 'services' ? 'Novo Serviço' : 'Novo Profissional'}</span>
        </button>
      </div>

      {/* Content */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        {activeTab === 'services' ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Serviço</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Descrição</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Duração</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Valor</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase text-center">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {services.map(s => (
                  <tr key={s.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-medium text-slate-800">{s.name}</td>
                    <td className="px-6 py-4 text-slate-500 text-sm max-w-xs truncate">{s.description}</td>
                    <td className="px-6 py-4 text-slate-600 text-sm">
                      <div className="flex items-center"><Clock size={14} className="mr-1 text-slate-400"/> {s.duration} min</div>
                    </td>
                    <td className="px-6 py-4 text-teal-600 font-bold text-sm">
                       R$ {s.price.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex items-center justify-center space-x-2">
                        <button onClick={() => openModal(s)} className="p-2 text-slate-400 hover:text-teal-600 hover:bg-teal-50 rounded-lg transition-colors"><Edit2 size={18} /></button>
                        <button onClick={() => handleDeleteClick(s.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={18} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
                {services.length === 0 && <tr><td colSpan={5} className="p-8 text-center text-slate-400">Nenhum serviço cadastrado.</td></tr>}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Profissional</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Especialidade</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Registro</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Contato</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase text-center">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {professionals.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                       <div className="flex items-center space-x-3">
                         <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xs">{p.name.charAt(0)}</div>
                         <span className="font-medium text-slate-800">{p.name}</span>
                       </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600 text-sm">{p.specialty}</td>
                    <td className="px-6 py-4 text-slate-500 text-sm font-mono bg-slate-50 px-2 rounded inline-block">{p.registrationNumber}</td>
                    <td className="px-6 py-4">
                       <div className="flex flex-col text-xs text-slate-500 space-y-1">
                         <span className="flex items-center"><Mail size={12} className="mr-1.5"/> {p.email}</span>
                         <span className="flex items-center"><Phone size={12} className="mr-1.5"/> {p.phone}</span>
                       </div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex items-center justify-center space-x-2">
                        <button onClick={() => openModal(p)} className="p-2 text-slate-400 hover:text-teal-600 hover:bg-teal-50 rounded-lg transition-colors"><Edit2 size={18} /></button>
                        <button onClick={() => handleDeleteClick(p.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={18} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
                {professionals.length === 0 && <tr><td colSpan={5} className="p-8 text-center text-slate-400">Nenhum profissional cadastrado.</td></tr>}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Main Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-xl shadow-2xl max-w-md w-full overflow-hidden">
            <div className="p-5 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-800">
                {editingId ? 'Editar' : 'Novo'} {activeTab === 'services' ? 'Serviço' : 'Profissional'}
              </h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:bg-slate-200 rounded-full p-1"><Trash2 size={0} /><span className="text-xl font-bold">&times;</span></button>
            </div>
            <form onSubmit={handleSave} className="p-6 space-y-4">
              {activeTab === 'services' ? (
                <>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nome do Serviço</label>
                    <input required type="text" value={serviceName} onChange={e => setServiceName(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="Ex: Consulta Geral" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Descrição</label>
                    <textarea value={serviceDesc} onChange={e => setServiceDesc(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" rows={3} placeholder="Detalhes do serviço..." />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                       <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Preço (R$)</label>
                       <div className="relative">
                         <DollarSign size={16} className="absolute left-3 top-3 text-slate-400"/>
                         <input required type="number" step="0.01" value={servicePrice} onChange={e => setServicePrice(e.target.value)} className="w-full border border-slate-300 p-2.5 pl-9 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                       </div>
                    </div>
                    <div>
                       <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duração (min)</label>
                       <div className="relative">
                         <Clock size={16} className="absolute left-3 top-3 text-slate-400"/>
                         <input required type="number" value={serviceDuration} onChange={e => setServiceDuration(e.target.value)} className="w-full border border-slate-300 p-2.5 pl-9 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                       </div>
                    </div>
                  </div>
                </>
              ) : (
                <>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Nome Completo</label>
                    <div className="relative">
                        <User size={18} className="absolute left-3 top-2.5 text-slate-400"/>
                        <input required type="text" value={profName} onChange={e => setProfName(e.target.value)} className="w-full border border-slate-300 p-2.5 pl-10 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="Dr. Nome Sobrenome" />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Especialidade</label>
                        <input required type="text" value={profSpecialty} onChange={e => setProfSpecialty(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="Ex: Fisioterapeuta" />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Registro (CRM/Outro)</label>
                        <input required type="text" value={profReg} onChange={e => setProfReg(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="12345/UF" />
                    </div>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Email</label>
                    <div className="relative">
                        <Mail size={18} className="absolute left-3 top-2.5 text-slate-400"/>
                        <input required type="email" value={profEmail} onChange={e => setProfEmail(e.target.value)} className="w-full border border-slate-300 p-2.5 pl-10 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                    </div>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Telefone</label>
                    <div className="relative">
                        <Phone size={18} className="absolute left-3 top-2.5 text-slate-400"/>
                        <input required type="tel" value={profPhone} onChange={e => setProfPhone(e.target.value)} className="w-full border border-slate-300 p-2.5 pl-10 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                    </div>
                  </div>
                </>
              )}
              <div className="pt-4 flex space-x-3">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-2.5 text-slate-600 bg-slate-100 rounded-lg font-medium hover:bg-slate-200">Cancelar</button>
                <button type="submit" className="flex-1 py-2.5 bg-teal-600 text-white rounded-lg font-bold hover:bg-teal-700 shadow-md">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm p-6 transform transition-all scale-100">
             <div className="flex flex-col items-center text-center">
                <div className="w-12 h-12 bg-red-100 text-red-500 rounded-full flex items-center justify-center mb-4">
                  <AlertCircle size={28} />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">Excluir Item?</h3>
                <p className="text-slate-500 mb-6">
                  Esta ação não poderá ser desfeita. O item será removido permanentemente.
                </p>
                <div className="flex w-full space-x-3">
                   <button 
                     onClick={() => setShowDeleteModal(false)} 
                     className="flex-1 py-2.5 bg-slate-100 text-slate-700 rounded-lg font-medium hover:bg-slate-200 transition-colors"
                   >
                     Cancelar
                   </button>
                   <button 
                     onClick={confirmDelete} 
                     className="flex-1 py-2.5 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 transition-colors shadow-lg shadow-red-500/30"
                   >
                     Excluir
                   </button>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Services;

export enum AppointmentType {
  AVALIACAO = 'Avaliação',
  CONSULTA = 'Consulta',
  RETORNO = 'Retorno',
  ACOMPANHAMENTO = 'Acompanhamento'
}

export interface Appointment {
  id: string;
  patientId: string;
  date: string;
  type: AppointmentType;
  serviceId?: string;
  weight: number;
  height: number;
  notes: string;
  price: number;
}

export interface Patient {
  id: string;
  name: string;
  email: string;
  phone: string;
  birthDate: string;
  createdAt: string;
  status?: string;
}

export enum TransactionType {
  INCOME = 'Entrada',
  EXPENSE = 'Saída'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  type: TransactionType;
  date: string;
  category: string;
}

export interface Service {
  id: string;
  name: string;
  description: string;
  price: number;
  duration: number; // minutes
}

export interface Professional {
  id: string;
  name: string;
  specialty: string;
  email: string;
  phone: string;
  registrationNumber: string; // CRM, CREFITO, etc.
}

export interface DashboardMetrics {
  totalPatients: number;
  activePatients: number; // Seen in last 60 days
  lostPatients: number; // Not seen in 60+ days
  totalRevenue: number;
  totalExpenses: number;
  netProfit: number;
  appointmentsByType: { name: string; value: number }[];
  revenueByMonth: { name: string; income: number; expense: number }[];
}

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType, Service } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp, Edit2, ChevronDown } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'form'>('list'); // Renamed 'new' to 'form'
  const [searchTerm, setSearchTerm] = useState('');

  // Patient Form States
  const [editingPatientId, setEditingPatientId] = useState<string | null>(null);
  const [patientName, setPatientName] = useState('');
  const [patientEmail, setPatientEmail] = useState('');
  const [patientPhone, setPatientPhone] = useState('');
  const [patientBirth, setPatientBirth] = useState('');
  const [patientStatus, setPatientStatus] = useState('Ativo');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [editingApptId, setEditingApptId] = useState<string | null>(null);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptServiceId, setApptServiceId] = useState('');
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
    setServices(StorageService.getServices());
  };

  // --- PATIENT ACTIONS ---

  const handleSavePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const patientData: Patient = {
      id: editingPatientId || '', // Empty ID triggers creation in StorageService, ID triggers update
      name: patientName,
      email: patientEmail,
      phone: patientPhone,
      birthDate: patientBirth,
      status: patientStatus,
      createdAt: editingPatientId && selectedPatient ? selectedPatient.createdAt : new Date().toISOString()
    };

    StorageService.savePatient(patientData);

    // If editing active patient, update the selected view
    if (selectedPatient && editingPatientId === selectedPatient.id) {
        setSelectedPatient(patientData);
    }

    refreshData();
    setView('list');
    resetPatientForm();
  };

  const startNewPatient = () => {
    resetPatientForm();
    setView('form');
  };

  const startEditPatient = (patient: Patient) => {
    setEditingPatientId(patient.id);
    setPatientName(patient.name);
    setPatientEmail(patient.email);
    setPatientPhone(patient.phone);
    setPatientBirth(patient.birthDate);
    setPatientStatus(patient.status || 'Ativo');
    setView('form');
  };

  const resetPatientForm = () => {
    setEditingPatientId(null);
    setPatientName('');
    setPatientEmail('');
    setPatientPhone('');
    setPatientBirth('');
    setPatientStatus('Ativo');
  };

  // --- APPOINTMENT ACTIONS ---

  const handleSaveAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;

    const apptData: Appointment = {
      id: editingApptId || '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      serviceId: apptServiceId,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };

    StorageService.saveAppointment(apptData);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed
    resetApptForm();
  };

  const startNewAppointment = () => {
    resetApptForm();
    setShowApptForm(true);
  };

  const startEditAppointment = (app: Appointment) => {
    setEditingApptId(app.id);
    setApptDate(app.date);
    setApptType(app.type);
    setApptServiceId(app.serviceId || '');
    setApptWeight(app.weight.toString());
    setApptHeight(app.height.toString());
    setApptNotes(app.notes);
    setApptPrice(app.price.toString());
    setShowApptForm(true);
  };

  const resetApptForm = () => {
    setEditingApptId(null);
    setApptDate(new Date().toISOString().split('T')[0]);
    setApptType(AppointmentType.CONSULTA);
    setApptServiceId('');
    setApptWeight('');
    setApptHeight('');
    setApptNotes('');
    setApptPrice('0');
  };

  // --- VIEW LOGIC ---

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patient: Patient) => {
    const pApps = appointments.filter(a => a.patientId === patient.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = patient.status;

    // Fallback logic if status is not set manually
    if (!status) {
        if (pApps.length > 0) {
            const lastAppDate = new Date(pApps[0].date);
            const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

            if (diffDays > 60) {
              status = 'Inativo';
            } else {
              status = 'Ativo';
            }
        } else {
            status = 'Novo';
        }
    }

    let statusColor = 'text-blue-500 bg-blue-50';
    if (status === 'Ativo') statusColor = 'text-green-500 bg-green-50';
    else if (status === 'Inativo') statusColor = 'text-red-500 bg-red-50';

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou email..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={startNewPatient}
            className="w-full md:w-auto flex items-center justify-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors shadow-sm font-medium"
          >
            <Plus size={20} />
            <span>Cadastrar Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Paciente</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Status</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Total Receita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Última Visita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((patient) => {
                  const { status, statusColor, totalSpent, lastApp } = getPatientMetrics(patient);
                  return (
                    <tr key={patient.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => handleSelectPatient(patient)}>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                            {patient.name.charAt(0)}
                          </div>
                          <div>
                            <span className="block font-medium text-slate-700">{patient.name}</span>
                            <span className="text-xs text-slate-400">{patient.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-medium border ${statusColor.replace('bg-', 'border-').replace('text-', 'border-opacity-20 ')} ${statusColor}`}>
                          {status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-slate-700 font-medium">
                          <TrendingUp size={14} className="mr-1 text-teal-500"/>
                          R$ {totalSpent.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-sm">
                        {lastApp ? new Date(lastApp.date).toLocaleDateString() : 'Nunca'}
                      </td>
                      <td className="px-6 py-4">
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleSelectPatient(patient); }}
                          className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                        >
                          Prontuário <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredPatients.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                      <div className="flex flex-col items-center">
                        <User size={48} className="text-slate-200 mb-2"/>
                        <p>Nenhum paciente encontrado.</p>
                        <button onClick={startNewPatient} className="mt-2 text-teal-600 hover:underline">Cadastrar o primeiro?</button>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT FORM (NEW OR EDIT)
  if (view === 'form') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar para Lista
        </button>
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
             <div className="bg-teal-100 p-2 rounded-lg text-teal-600"><User size={24}/></div>
             <div>
               <h2 className="text-xl font-bold text-slate-800">{editingPatientId ? 'Editar Paciente' : 'Novo Paciente'}</h2>
               <p className="text-sm text-slate-500">{editingPatientId ? 'Atualize os dados abaixo.' : 'Preencha os dados básicos para iniciar o prontuário.'}</p>
             </div>
          </div>
          <form onSubmit={handleSavePatient} className="p-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" placeholder="Ex: João da Silva" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientName} onChange={e => setPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" placeholder="joao@email.com" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientEmail} onChange={e => setPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone / WhatsApp</label>
                <input required type="tel" placeholder="(11) 99999-9999" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientPhone} onChange={e => setPatientPhone(e.target.value)} />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                <input required type="date" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientBirth} onChange={e => setPatientBirth(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                <div className="relative">
                    <select 
                        value={patientStatus} 
                        onChange={e => setPatientStatus(e.target.value)} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all appearance-none bg-white text-slate-700"
                    >
                        <option value="Ativo">Ativo</option>
                        <option value="Inativo">Inativo</option>
                        <option value="Novo">Novo</option>
                    </select>
                    <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                    </div>
                </div>
              </div>
            </div>
            <div className="pt-6 flex justify-end space-x-3 border-t border-slate-100 mt-6">
              <button type="button" onClick={() => setView('list')} className="px-6 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
              <button type="submit" className="px-6 py-2.5 bg-teal-600 text-white rounded-lg hover:bg-teal-700 font-medium shadow-md transition-colors flex items-center">
                <CheckCircle size={18} className="mr-2"/> {editingPatientId ? 'Atualizar Dados' : 'Salvar Cadastro'}
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT DETAIL
  if (view === 'detail' && selectedPatient) {
    const patientApps = appointments
      .filter(a => a.patientId === selectedPatient.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const { status, statusColor } = getPatientMetrics(selectedPatient);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div className="w-full md:w-auto">
             <button onClick={() => setView('list')} className="mb-2 text-slate-500 flex items-center hover:text-slate-800 text-sm font-medium">
               <ChevronRight className="rotate-180 mr-1" size={16}/> Voltar para lista
             </button>
             <div className="flex items-center space-x-3">
               <h2 className="text-3xl font-bold text-slate-800">{selectedPatient.name}</h2>
               <span className={`px-2 py-0.5 rounded text-xs font-bold border ${statusColor.replace('bg-', 'border-')} ${statusColor}`}>{status}</span>
               <button onClick={() => startEditPatient(selectedPatient)} className="text-slate-400 hover:text-teal-600 transition-colors p-1 rounded hover:bg-slate-100">
                 <Edit2 size={18} />
               </button>
             </div>
             <p className="text-slate-500 mt-1 flex items-center space-x-2">
                <span>{selectedPatient.email}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span>{selectedPatient.phone}</span>
             </p>
           </div>
           <button 
             onClick={startNewAppointment}
             className="bg-teal-600 text-white px-5 py-2.5 rounded-lg hover:bg-teal-700 flex items-center space-x-2 shadow-sm font-medium transition-all transform hover:-translate-y-0.5"
           >
             <Plus size={20} /> <span>Novo Atendimento</span>
           </button>
        </div>

        {/* AI Summary Block */}
        <div className="bg-gradient-to-r from-indigo-50 to-purple-50 border border-indigo-100 p-5 rounded-xl shadow-sm">
           <div className="flex justify-between items-center mb-3">
             <div className="flex items-center space-x-2 text-indigo-900 font-bold">
               <Sparkles size={18} className="text-purple-600" /> <span>Análise Inteligente do Prontuário</span>
             </div>
             <button onClick={handleGenerateSummary} disabled={loadingAi} className="text-xs bg-white border border-indigo-200 text-indigo-700 px-3 py-1 rounded hover:bg-indigo-50 font-medium disabled:opacity-50 transition-colors">
               {loadingAi ? 'ANALISANDO...' : 'GERAR RESUMO IA'}
             </button>
           </div>
           <p className="text-sm text-slate-700 leading-relaxed bg-white/50 p-3 rounded-lg border border-indigo-50/50">
             {aiSummary || "Clique em 'Gerar Resumo IA' para analisar a evolução do peso, frequência e notas clínicas deste paciente automaticamente."}
           </p>
        </div>

        {/* History Timeline */}
        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-700 flex items-center"><FileText size={20} className="mr-2 text-slate-400"/> Histórico de Consultas</h3>
          {patientApps.length === 0 ? (
            <div className="bg-white p-12 rounded-xl text-center border-2 border-dashed border-slate-200">
              <div className="mx-auto w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-3">
                <Calendar size={32} />
              </div>
              <h4 className="text-slate-500 font-medium">Nenhum atendimento registrado</h4>
              <p className="text-slate-400 text-sm mt-1">Clique em "Novo Atendimento" para iniciar.</p>
            </div>
          ) : (
            patientApps.map((app) => (
              <div key={app.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow group">
                <div className="p-5">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-4">
                    <div className="flex items-center space-x-3">
                       <div className={`p-2 rounded-lg ${
                         app.type === AppointmentType.AVALIACAO ? 'bg-purple-100 text-purple-700' : 
                         app.type === AppointmentType.CONSULTA ? 'bg-blue-100 text-blue-700' :
                         'bg-green-100 text-green-700'
                       }`}>
                         <Calendar size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-slate-800 text-lg">{app.type}</h4>
                         <p className="text-slate-500 text-sm">{new Date(app.date).toLocaleDateString()} • {new Date(app.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                         {app.serviceId && services.find(s => s.id === app.serviceId) && (
                            <span className="text-xs text-teal-600 bg-teal-50 px-2 py-0.5 rounded-full mt-1 inline-block">
                                {services.find(s => s.id === app.serviceId)?.name}
                            </span>
                         )}
                       </div>
                    </div>
                    <div className="flex items-center space-x-4">
                        <div className="flex items-center space-x-6 bg-slate-50 px-4 py-2 rounded-lg border border-slate-100">
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Peso</span>
                            <span className="font-bold text-slate-700 flex items-center"><Scale size={14} className="mr-1 text-slate-400"/> {app.weight} kg</span>
                        </div>
                        <div className="w-px h-8 bg-slate-200"></div>
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Altura</span>
                            <span className="font-bold text-slate-700 flex items-center"><Ruler size={14} className="mr-1 text-slate-400"/> {app.height} cm</span>
                        </div>
                        </div>
                        <button onClick={() => startEditAppointment(app)} className="text-slate-300 hover:text-teal-600 transition-colors p-2 hover:bg-slate-50 rounded-full">
                            <Edit2 size={18} />
                        </button>
                    </div>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 text-slate-700 text-sm leading-relaxed">
                    <span className="font-semibold text-slate-900 block mb-1">Anotações Clínicas:</span>
                    {app.notes}
                  </div>
                  <div className="mt-3 text-right">
                     <span className="text-xs text-slate-400 font-medium">Valor da Consulta: </span>
                     <span className="text-sm font-bold text-teal-600">R$ {app.price.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Modal for Appointment (New/Edit) */}
        {showApptForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-lg font-bold text-slate-800 flex items-center">
                    {editingApptId ? <Edit2 size={18} className="mr-2 text-teal-600"/> : <Plus size={18} className="mr-2 text-teal-600"/>} 
                    {editingApptId ? 'Editar Atendimento' : 'Registrar Atendimento'}
                </h3>
                <button onClick={() => setShowApptForm(false)} className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-1 rounded-full border border-slate-200 hover:bg-slate-100"><X size={20}/></button>
              </div>
              <div className="p-6 overflow-y-auto">
                <form onSubmit={handleSaveAppointment} className="space-y-5">

                  {/* Service Selection */}
                  <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Serviço (Opcional)</label>
                       <div className="relative">
                         <select 
                            value={apptServiceId} 
                            onChange={(e) => {
                                const sId = e.target.value;
                                setApptServiceId(sId);
                                const s = services.find(srv => srv.id === sId);
                                if(s) setApptPrice(s.price.toString());
                            }} 
                            className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                         >
                           <option value="">Selecione um serviço...</option>
                           {services.map(s => <option key={s.id} value={s.id}>{s.name} - R$ {s.price.toFixed(2)}</option>)}
                         </select>
                         <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                           <ChevronDown size={16} />
                         </div>
                       </div>
                  </div>

                  <div className="grid grid-cols-2 gap-5">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data do Atendimento</label>
                       <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                       <div className="relative">
                         <select 
                            value={apptType} 
                            onChange={e => setApptType(e.target.value as AppointmentType)} 
                            className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                         >
                           {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                         </select>
                         <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                           <ChevronDown size={16} />
                         </div>
                       </div>
                     </div>
                  </div>

                  <div className="p-4 bg-slate-50 rounded-lg border border-slate-100 grid grid-cols-3 gap-4">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                       <div className="relative">
                         <input required type="number" step="0.1" placeholder="0.0" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border border-slate-300 p-2 pl-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                       </div>
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                       <input required type="number" placeholder="0" value={apptHeight} onChange={e => setApptHeight(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                       <input required type="number" placeholder="0.00" value={apptPrice} onChange={e => setApptPrice(e.target.value)} className="w-full border border-slate-300 p-2 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" />
                     </div>
                  </div>

                  <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Descrição / Evolução Clínica</label>
                     <textarea required rows={5} placeholder="Descreva os detalhes da consulta, queixas e observações..." value={apptNotes} onChange={e => setApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none"></textarea>
                  </div>

                  <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                    <CheckCircle size={20} className="mr-2" /> {editingApptId ? 'Atualizar Atendimento' : 'Salvar Atendimento'}
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
};

export default Patients;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType, Service } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp, Edit2, ChevronDown } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'form'>('list'); // Renamed 'new' to 'form'
  const [searchTerm, setSearchTerm] = useState('');

  // Patient Form States
  const [editingPatientId, setEditingPatientId] = useState<string | null>(null);
  const [patientName, setPatientName] = useState('');
  const [patientEmail, setPatientEmail] = useState('');
  const [patientPhone, setPatientPhone] = useState('');
  const [patientBirth, setPatientBirth] = useState('');
  const [patientStatus, setPatientStatus] = useState('Ativo');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [editingApptId, setEditingApptId] = useState<string | null>(null);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptServiceId, setApptServiceId] = useState('');
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
    setServices(StorageService.getServices());
  };

  // --- PATIENT ACTIONS ---

  const handleSavePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const patientData: Patient = {
      id: editingPatientId || '', // Empty ID triggers creation in StorageService, ID triggers update
      name: patientName,
      email: patientEmail,
      phone: patientPhone,
      birthDate: patientBirth,
      status: patientStatus,
      createdAt: editingPatientId && selectedPatient ? selectedPatient.createdAt : new Date().toISOString()
    };

    StorageService.savePatient(patientData);

    // If editing active patient, update the selected view
    if (selectedPatient && editingPatientId === selectedPatient.id) {
        setSelectedPatient(patientData);
    }

    refreshData();
    setView('list');
    resetPatientForm();
  };

  const startNewPatient = () => {
    resetPatientForm();
    setView('form');
  };

  const startEditPatient = (patient: Patient) => {
    setEditingPatientId(patient.id);
    setPatientName(patient.name);
    setPatientEmail(patient.email);
    setPatientPhone(patient.phone);
    setPatientBirth(patient.birthDate);
    setPatientStatus(patient.status || 'Ativo');
    setView('form');
  };

  const resetPatientForm = () => {
    setEditingPatientId(null);
    setPatientName('');
    setPatientEmail('');
    setPatientPhone('');
    setPatientBirth('');
    setPatientStatus('Ativo');
  };

  // --- APPOINTMENT ACTIONS ---

  const handleSaveAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;

    const apptData: Appointment = {
      id: editingApptId || '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      serviceId: apptServiceId,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };

    StorageService.saveAppointment(apptData);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed
    resetApptForm();
  };

  const startNewAppointment = () => {
    resetApptForm();
    setShowApptForm(true);
  };

  const startEditAppointment = (app: Appointment) => {
    setEditingApptId(app.id);
    setApptDate(app.date);
    setApptType(app.type);
    setApptServiceId(app.serviceId || '');
    setApptWeight(app.weight.toString());
    setApptHeight(app.height.toString());
    setApptNotes(app.notes);
    setApptPrice(app.price.toString());
    setShowApptForm(true);
  };

  const resetApptForm = () => {
    setEditingApptId(null);
    setApptDate(new Date().toISOString().split('T')[0]);
    setApptType(AppointmentType.CONSULTA);
    setApptServiceId('');
    setApptWeight('');
    setApptHeight('');
    setApptNotes('');
    setApptPrice('0');
  };

  // --- VIEW LOGIC ---

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patient: Patient) => {
    const pApps = appointments.filter(a => a.patientId === patient.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = patient.status;

    // Fallback logic if status is not set manually
    if (!status) {
        if (pApps.length > 0) {
            const lastAppDate = new Date(pApps[0].date);
            const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

            if (diffDays > 60) {
              status = 'Inativo';
            } else {
              status = 'Ativo';
            }
        } else {
            status = 'Novo';
        }
    }

    let statusColor = 'text-blue-500 bg-blue-50';
    if (status === 'Ativo') statusColor = 'text-green-500 bg-green-50';
    else if (status === 'Inativo') statusColor = 'text-red-500 bg-red-50';

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-3 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou email..." 
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={startNewPatient}
            className="w-full md:w-auto flex items-center justify-center space-x-2 bg-teal-600 text-white px-4 py-2 rounded-lg hover:bg-teal-700 transition-colors shadow-sm font-medium"
          >
            <Plus size={20} />
            <span>Cadastrar Paciente</span>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Paciente</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Status</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Total Receita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Última Visita</th>
                  <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((patient) => {
                  const { status, statusColor, totalSpent, lastApp } = getPatientMetrics(patient);
                  return (
                    <tr key={patient.id} className="hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => handleSelectPatient(patient)}>
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                            {patient.name.charAt(0)}
                          </div>
                          <div>
                            <span className="block font-medium text-slate-700">{patient.name}</span>
                            <span className="text-xs text-slate-400">{patient.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-medium border ${statusColor.replace('bg-', 'border-').replace('text-', 'border-opacity-20 ')} ${statusColor}`}>
                          {status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center text-slate-700 font-medium">
                          <TrendingUp size={14} className="mr-1 text-teal-500"/>
                          R$ {totalSpent.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-sm">
                        {lastApp ? new Date(lastApp.date).toLocaleDateString() : 'Nunca'}
                      </td>
                      <td className="px-6 py-4">
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleSelectPatient(patient); }}
                          className="text-teal-600 hover:text-teal-800 font-medium text-sm flex items-center"
                        >
                          Prontuário <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
                {filteredPatients.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                      <div className="flex flex-col items-center">
                        <User size={48} className="text-slate-200 mb-2"/>
                        <p>Nenhum paciente encontrado.</p>
                        <button onClick={startNewPatient} className="mt-2 text-teal-600 hover:underline">Cadastrar o primeiro?</button>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT FORM (NEW OR EDIT)
  if (view === 'form') {
    return (
      <div className="max-w-2xl mx-auto">
        <button onClick={() => setView('list')} className="mb-4 text-slate-500 flex items-center hover:text-slate-800">
           <ChevronRight className="rotate-180 mr-1" size={20}/> Voltar para Lista
        </button>
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
             <div className="bg-teal-100 p-2 rounded-lg text-teal-600"><User size={24}/></div>
             <div>
               <h2 className="text-xl font-bold text-slate-800">{editingPatientId ? 'Editar Paciente' : 'Novo Paciente'}</h2>
               <p className="text-sm text-slate-500">{editingPatientId ? 'Atualize os dados abaixo.' : 'Preencha os dados básicos para iniciar o prontuário.'}</p>
             </div>
          </div>
          <form onSubmit={handleSavePatient} className="p-8 space-y-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
              <input required type="text" placeholder="Ex: João da Silva" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientName} onChange={e => setPatientName(e.target.value)} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input required type="email" placeholder="joao@email.com" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientEmail} onChange={e => setPatientEmail(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone / WhatsApp</label>
                <input required type="tel" placeholder="(11) 99999-9999" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientPhone} onChange={e => setPatientPhone(e.target.value)} />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                <input required type="date" className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all" value={patientBirth} onChange={e => setPatientBirth(e.target.value)} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
                <div className="relative">
                    <select 
                        value={patientStatus} 
                        onChange={e => setPatientStatus(e.target.value)} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 outline-none transition-all appearance-none bg-white text-slate-700"
                    >
                        <option value="Ativo">Ativo</option>
                        <option value="Inativo">Inativo</option>
                        <option value="Novo">Novo</option>
                    </select>
                    <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                    </div>
                </div>
              </div>
            </div>
            <div className="pt-6 flex justify-end space-x-3 border-t border-slate-100 mt-6">
              <button type="button" onClick={() => setView('list')} className="px-6 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">Cancelar</button>
              <button type="submit" className="px-6 py-2.5 bg-teal-600 text-white rounded-lg hover:bg-teal-700 font-medium shadow-md transition-colors flex items-center">
                <CheckCircle size={18} className="mr-2"/> {editingPatientId ? 'Atualizar Dados' : 'Salvar Cadastro'}
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // VIEW: PATIENT DETAIL
  if (view === 'detail' && selectedPatient) {
    const patientApps = appointments
      .filter(a => a.patientId === selectedPatient.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    const { status, statusColor } = getPatientMetrics(selectedPatient);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div className="w-full md:w-auto">
             <button onClick={() => setView('list')} className="mb-2 text-slate-500 flex items-center hover:text-slate-800 text-sm font-medium">
               <ChevronRight className="rotate-180 mr-1" size={16}/> Voltar para lista
             </button>
             <div className="flex items-center space-x-3">
               <h2 className="text-3xl font-bold text-slate-800">{selectedPatient.name}</h2>
               <span className={`px-2 py-0.5 rounded text-xs font-bold border ${statusColor.replace('bg-', 'border-')} ${statusColor}`}>{status}</span>
               <button onClick={() => startEditPatient(selectedPatient)} className="text-slate-400 hover:text-teal-600 transition-colors p-1 rounded hover:bg-slate-100">
                 <Edit2 size={18} />
               </button>
             </div>
             <p className="text-slate-500 mt-1 flex items-center space-x-2">
                <span>{selectedPatient.email}</span>
                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                <span>{selectedPatient.phone}</span>
             </p>
           </div>
           <button 
             onClick={startNewAppointment}
             className="bg-teal-600 text-white px-5 py-2.5 rounded-lg hover:bg-teal-700 flex items-center space-x-2 shadow-sm font-medium transition-all transform hover:-translate-y-0.5"
           >
             <Plus size={20} /> <span>Novo Atendimento</span>
           </button>
        </div>

        {/* AI Summary Block */}
        <div className="bg-gradient-to-r from-indigo-50 to-purple-50 border border-indigo-100 p-5 rounded-xl shadow-sm">
           <div className="flex justify-between items-center mb-3">
             <div className="flex items-center space-x-2 text-indigo-900 font-bold">
               <Sparkles size={18} className="text-purple-600" /> <span>Análise Inteligente do Prontuário</span>
             </div>
             <button onClick={handleGenerateSummary} disabled={loadingAi} className="text-xs bg-white border border-indigo-200 text-indigo-700 px-3 py-1 rounded hover:bg-indigo-50 font-medium disabled:opacity-50 transition-colors">
               {loadingAi ? 'ANALISANDO...' : 'GERAR RESUMO IA'}
             </button>
           </div>
           <p className="text-sm text-slate-700 leading-relaxed bg-white/50 p-3 rounded-lg border border-indigo-50/50">
             {aiSummary || "Clique em 'Gerar Resumo IA' para analisar a evolução do peso, frequência e notas clínicas deste paciente automaticamente."}
           </p>
        </div>

        {/* History Timeline */}
        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-700 flex items-center"><FileText size={20} className="mr-2 text-slate-400"/> Histórico de Consultas</h3>
          {patientApps.length === 0 ? (
            <div className="bg-white p-12 rounded-xl text-center border-2 border-dashed border-slate-200">
              <div className="mx-auto w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-3">
                <Calendar size={32} />
              </div>
              <h4 className="text-slate-500 font-medium">Nenhum atendimento registrado</h4>
              <p className="text-slate-400 text-sm mt-1">Clique em "Novo Atendimento" para iniciar.</p>
            </div>
          ) : (
            patientApps.map((app) => (
              <div key={app.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:shadow-md transition-shadow group">
                <div className="p-5">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-4">
                    <div className="flex items-center space-x-3">
                       <div className={`p-2 rounded-lg ${
                         app.type === AppointmentType.AVALIACAO ? 'bg-purple-100 text-purple-700' : 
                         app.type === AppointmentType.CONSULTA ? 'bg-blue-100 text-blue-700' :
                         'bg-green-100 text-green-700'
                       }`}>
                         <Calendar size={20} />
                       </div>
                       <div>
                         <h4 className="font-bold text-slate-800 text-lg">{app.type}</h4>
                         <p className="text-slate-500 text-sm">{new Date(app.date).toLocaleDateString()} • {new Date(app.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                         {app.serviceId && services.find(s => s.id === app.serviceId) && (
                            <span className="text-xs text-teal-600 bg-teal-50 px-2 py-0.5 rounded-full mt-1 inline-block">
                                {services.find(s => s.id === app.serviceId)?.name}
                            </span>
                         )}
                       </div>
                    </div>
                    <div className="flex items-center space-x-4">
                        <div className="flex items-center space-x-6 bg-slate-50 px-4 py-2 rounded-lg border border-slate-100">
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Peso</span>
                            <span className="font-bold text-slate-700 flex items-center"><Scale size={14} className="mr-1 text-slate-400"/> {app.weight} kg</span>
                        </div>
                        <div className="w-px h-8 bg-slate-200"></div>
                        <div className="text-center">
                            <span className="text-xs text-slate-400 uppercase font-bold block mb-0.5">Altura</span>
                            <span className="font-bold text-slate-700 flex items-center"><Ruler size={14} className="mr-1 text-slate-400"/> {app.height} cm</span>
                        </div>
                        </div>
                        <button onClick={() => startEditAppointment(app)} className="text-slate-300 hover:text-teal-600 transition-colors p-2 hover:bg-slate-50 rounded-full">
                            <Edit2 size={18} />
                        </button>
                    </div>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 text-slate-700 text-sm leading-relaxed">
                    <span className="font-semibold text-slate-900 block mb-1">Anotações Clínicas:</span>
                    {app.notes}
                  </div>
                  <div className="mt-3 text-right">
                     <span className="text-xs text-slate-400 font-medium">Valor da Consulta: </span>
                     <span className="text-sm font-bold text-teal-600">R$ {app.price.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Modal for Appointment (New/Edit) */}
        {showApptForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="text-lg font-bold text-slate-800 flex items-center">
                    {editingApptId ? <Edit2 size={18} className="mr-2 text-teal-600"/> : <Plus size={18} className="mr-2 text-teal-600"/>} 
                    {editingApptId ? 'Editar Atendimento' : 'Registrar Atendimento'}
                </h3>
                <button onClick={() => setShowApptForm(false)} className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-1 rounded-full border border-slate-200 hover:bg-slate-100"><X size={20}/></button>
              </div>
              <div className="p-6 overflow-y-auto">
                <form onSubmit={handleSaveAppointment} className="space-y-5">

                  {/* Service Selection */}
                  <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Serviço (Opcional)</label>
                       <div className="relative">
                         <select 
                            value={apptServiceId} 
                            onChange={(e) => {
                                const sId = e.target.value;
                                setApptServiceId(sId);
                                const s = services.find(srv => srv.id === sId);
                                if(s) setApptPrice(s.price.toString());
                            }} 
                            className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                         >
                           <option value="">Selecione um serviço...</option>
                           {services.map(s => <option key={s.id} value={s.id}>{s.name} - R$ {s.price.toFixed(2)}</option>)}
                         </select>
                         <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                           <ChevronDown size={16} />
                         </div>
                       </div>
                  </div>

                  <div className="grid grid-cols-2 gap-5">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data do Atendimento</label>
                       <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                       <div className="relative">
                         <select 
                            value={apptType} 
                            onChange={e => setApptType(e.target.value as AppointmentType)} 
                            className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                         >
                           {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                         </select>
                         <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                           <ChevronDown size={16} />
                         </div>
                       </div>
                     </div>
                  </div>

                  <div className="grid grid-cols-3 gap-4">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                       <div className="relative">
                         <input required type="number" step="0.1" placeholder="0.0" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                       </div>
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                       <input required type="number" placeholder="0" value={apptHeight} onChange={e => setApptHeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                       <input required type="number" placeholder="0.00" value={apptPrice} onChange={e => setApptPrice(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                  </div>

                  <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Descrição / Evolução Clínica</label>
                     <textarea required rows={5} placeholder="Descreva os detalhes da consulta, queixas e observações..." value={apptNotes} onChange={e => setApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none bg-white text-slate-700"></textarea>
                  </div>

                  <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                    <CheckCircle size={20} className="mr-2" /> {editingApptId ? 'Atualizar Atendimento' : 'Salvar Atendimento'}
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
};

export default Patients;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Patient, Appointment, AppointmentType, Service } from '../types';
import { Search, Plus, User, Calendar, Ruler, Scale, FileText, ChevronRight, X, Sparkles, AlertCircle, CheckCircle, TrendingUp, Edit2, ChevronDown } from 'lucide-react';
import { GeminiService } from '../services/geminiService';

const Patients: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [view, setView] = useState<'list' | 'detail' | 'form'>('list'); // Renamed 'new' to 'form'
  const [searchTerm, setSearchTerm] = useState('');

  // Patient Form States
  const [editingPatientId, setEditingPatientId] = useState<string | null>(null);
  const [patientName, setPatientName] = useState('');
  const [patientEmail, setPatientEmail] = useState('');
  const [patientPhone, setPatientPhone] = useState('');
  const [patientBirth, setPatientBirth] = useState('');
  const [patientStatus, setPatientStatus] = useState('Ativo');

  // Appointment Form States
  const [showApptForm, setShowApptForm] = useState(false);
  const [editingApptId, setEditingApptId] = useState<string | null>(null);
  const [apptType, setApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [apptDate, setApptDate] = useState(new Date().toISOString().split('T')[0]);
  const [apptServiceId, setApptServiceId] = useState('');
  const [apptWeight, setApptWeight] = useState('');
  const [apptHeight, setApptHeight] = useState('');
  const [apptNotes, setApptNotes] = useState('');
  const [apptPrice, setApptPrice] = useState('0');

  // AI Summary
  const [aiSummary, setAiSummary] = useState('');
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setPatients(StorageService.getPatients());
    setAppointments(StorageService.getAppointments());
    setServices(StorageService.getServices());
  };

  // --- PATIENT ACTIONS ---

  const handleSavePatient = (e: React.FormEvent) => {
    e.preventDefault();
    const patientData: Patient = {
      id: editingPatientId || '', // Empty ID triggers creation in StorageService, ID triggers update
      name: patientName,
      email: patientEmail,
      phone: patientPhone,
      birthDate: patientBirth,
      status: patientStatus,
      createdAt: editingPatientId && selectedPatient ? selectedPatient.createdAt : new Date().toISOString()
    };

    StorageService.savePatient(patientData);

    // If editing active patient, update the selected view
    if (selectedPatient && editingPatientId === selectedPatient.id) {
        setSelectedPatient(patientData);
    }

    refreshData();
    setView('list');
    resetPatientForm();
  };

  const startNewPatient = () => {
    resetPatientForm();
    setView('form');
  };

  const startEditPatient = (patient: Patient) => {
    setEditingPatientId(patient.id);
    setPatientName(patient.name);
    setPatientEmail(patient.email);
    setPatientPhone(patient.phone);
    setPatientBirth(patient.birthDate);
    setPatientStatus(patient.status || 'Ativo');
    setView('form');
  };

  const resetPatientForm = () => {
    setEditingPatientId(null);
    setPatientName('');
    setPatientEmail('');
    setPatientPhone('');
    setPatientBirth('');
    setPatientStatus('Ativo');
  };

  // --- APPOINTMENT ACTIONS ---

  const handleSaveAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;

    const apptData: Appointment = {
      id: editingApptId || '',
      patientId: selectedPatient.id,
      date: apptDate,
      type: apptType,
      serviceId: apptServiceId,
      weight: Number(apptWeight),
      height: Number(apptHeight),
      notes: apptNotes,
      price: Number(apptPrice)
    };

    StorageService.saveAppointment(apptData);
    refreshData();
    setShowApptForm(false);
    setAiSummary(''); // Clear old summary as data changed
    resetApptForm();
  };

  const startNewAppointment = () => {
    resetApptForm();
    setShowApptForm(true);
  };

  const startEditAppointment = (app: Appointment) => {
    setEditingApptId(app.id);
    setApptDate(app.date);
    setApptType(app.type);
    setApptServiceId(app.serviceId || '');
    setApptWeight(app.weight.toString());
    setApptHeight(app.height.toString());
    setApptNotes(app.notes);
    setApptPrice(app.price.toString());
    setShowApptForm(true);
  };

  const resetApptForm = () => {
    setEditingApptId(null);
    setApptDate(new Date().toISOString().split('T')[0]);
    setApptType(AppointmentType.CONSULTA);
    setApptServiceId('');
    setApptWeight('');
    setApptHeight('');
    setApptNotes('');
    setApptPrice('0');
  };

  // --- VIEW LOGIC ---

  const handleSelectPatient = (p: Patient) => {
    setSelectedPatient(p);
    setView('detail');
    setAiSummary('');
  };

  const handleGenerateSummary = async () => {
    if(!selectedPatient) return;
    setLoadingAi(true);
    const patientApps = appointments.filter(a => a.patientId === selectedPatient.id);
    const summary = await GeminiService.getPatientSummary(selectedPatient, patientApps);
    setAiSummary(summary);
    setLoadingAi(false);
  }

  // Helper to calculate patient status and value
  const getPatientMetrics = (patient: Patient) => {
    const pApps = appointments.filter(a => a.patientId === patient.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    const totalSpent = pApps.reduce((sum, app) => sum + app.price, 0);

    let status = patient.status;

    // Fallback logic if status is not set manually
    if (!status) {
        if (pApps.length > 0) {
            const lastAppDate = new Date(pApps[0].date);
            const diffDays = Math.ceil((new Date().getTime() - lastAppDate.getTime()) / (1000 * 3600 * 24));

            if (diffDays > 60) {
              status = 'Inativo';
            } else {
              status = 'Ativo';
            }
        } else {
            status = 'Novo';
        }
    }

    let statusColor = 'text-blue-500 bg-blue-50';
    if (status === 'Ativo') statusColor = 'text-green-500 bg-green-50';
    else if (status === 'Inativo') statusColor = 'text-red-500 bg-red-50';

    return { totalSpent, status, statusColor, lastApp: pApps[0] };
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    p.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // VIEW: PATIENT LIST
  if (view === 'list') {
    return (
