                           <option value="">Selecione um serviço...</option>
                           {services.map(s => <option key={s.id} value={s.id}>{s.name} - R$ {s.price.toFixed(2)}</option>)}
                         </select>
                         <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                           <ChevronDown size={16} />
                         </div>
                       </div>
                  </div>

                  <div className="grid grid-cols-2 gap-5">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data</label>
                       <input required type="date" value={apptDate} onChange={e => setApptDate(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Horário</label>
                       <input required type="time" value={apptTime} onChange={e => setApptTime(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                  </div>

                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                    <div className="relative">
                        <select 
                        value={apptType} 
                        onChange={e => setApptType(e.target.value as AppointmentType)} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                        >
                        {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                        <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                        </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-3 gap-4">
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                       <div className="relative">
                         <input required type="number" step="0.1" placeholder="0.0" value={apptWeight} onChange={e => setApptWeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                       </div>
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                       <input required type="number" placeholder="0" value={apptHeight} onChange={e => setApptHeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                     <div>
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                       <input required type="number" placeholder="0.00" value={apptPrice} onChange={e => setApptPrice(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                     </div>
                  </div>

                  <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Descrição / Evolução Clínica</label>
                     <textarea required rows={5} placeholder="Descreva os detalhes da consulta, queixas e observações..." value={apptNotes} onChange={e => setApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none bg-white text-slate-700"></textarea>
                  </div>

                  <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                    <CheckCircle size={20} className="mr-2" /> {editingApptId ? 'Atualizar Atendimento' : 'Salvar Atendimento'}
                  </button>
                </form>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
};

export default Patients;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Appointment, Patient, Service, AppointmentType } from '../types';
import { ChevronLeft, ChevronRight, Plus, Calendar as CalendarIcon, Clock, User, CheckCircle, X, ChevronDown, Scale, Ruler } from 'lucide-react';

const Agenda: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(new Date());

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [services, setServices] = useState<Service[]>([]);

  // Form State
  const [showModal, setShowModal] = useState(false);
  const [newApptPatientId, setNewApptPatientId] = useState('');
  const [newApptServiceId, setNewApptServiceId] = useState('');
  const [newApptTime, setNewApptTime] = useState('09:00');
  const [newApptType, setNewApptType] = useState<AppointmentType>(AppointmentType.CONSULTA);
  const [newApptPrice, setNewApptPrice] = useState('0');
  const [newApptNotes, setNewApptNotes] = useState('');
  const [newApptWeight, setNewApptWeight] = useState('');
  const [newApptHeight, setNewApptHeight] = useState('');

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setAppointments(StorageService.getAppointments());
    setPatients(StorageService.getPatients());
    setServices(StorageService.getServices());
  };

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month + 1, 0).getDate();
  };

  const getFirstDayOfMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month, 1).getDay();
  };

  const changeMonth = (offset: number) => {
    const newDate = new Date(currentDate.setMonth(currentDate.getMonth() + offset));
    setCurrentDate(new Date(newDate));
  };

  const handleDateClick = (day: number) => {
    const newDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
    setSelectedDate(newDate);
  };

  const getAppointmentsForDate = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    return appointments
      .filter(a => a.date === dateStr)
      .sort((a, b) => (a.time || '00:00').localeCompare(b.time || '00:00'));
  };

  const handleCreateAppointment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newApptPatientId) return;

    const newAppt: Appointment = {
      id: Math.random().toString(36).substr(2, 9),
      patientId: newApptPatientId,
      date: selectedDate.toISOString().split('T')[0],
      time: newApptTime,
      type: newApptType,
      serviceId: newApptServiceId,
      weight: Number(newApptWeight),
      height: Number(newApptHeight),
      notes: newApptNotes,
      price: Number(newApptPrice)
    };

    StorageService.saveAppointment(newAppt);
    refreshData();
    setShowModal(false);

    // Reset form
    setNewApptPatientId('');
    setNewApptServiceId('');
    setNewApptNotes('');
    setNewApptWeight('');
    setNewApptHeight('');
  };

  const openNewApptModal = () => {
    setNewApptTime('09:00');
    setNewApptPrice('0');
    setNewApptType(AppointmentType.CONSULTA);
    setShowModal(true);
  }

  // Calendar Grid Logic
  const daysInMonth = getDaysInMonth(currentDate);
  const firstDay = getFirstDayOfMonth(currentDate);
  const days = [];

  // Empty slots for days before start of month
  for (let i = 0; i < firstDay; i++) {
    days.push(<div key={`empty-${i}`} className="h-24 bg-slate-50/50 border border-slate-100"></div>);
  }

  // Days of month
  for (let d = 1; d <= daysInMonth; d++) {
    const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), d);
    const dateStr = date.toISOString().split('T')[0];
    const isToday = new Date().toDateString() === date.toDateString();
    const isSelected = selectedDate.toDateString() === date.toDateString();

    const dailyApps = appointments.filter(a => a.date === dateStr);

    days.push(
      <div 
        key={d} 
        onClick={() => handleDateClick(d)}
        className={`h-24 border border-slate-100 p-2 cursor-pointer transition-colors relative group ${isSelected ? 'bg-teal-50 border-teal-200' : 'hover:bg-slate-50 bg-white'}`}
      >
        <div className="flex justify-between items-start">
           <span className={`text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full ${isToday ? 'bg-teal-600 text-white' : 'text-slate-700'}`}>
             {d}
           </span>
           {dailyApps.length > 0 && (
             <span className="text-xs bg-indigo-100 text-indigo-700 px-1.5 py-0.5 rounded-full font-bold">
               {dailyApps.length}
             </span>
           )}
        </div>
        <div className="mt-2 space-y-1">
            {dailyApps.slice(0, 2).map((app, idx) => {
                 const patient = patients.find(p => p.id === app.patientId);
                 return (
                    <div key={idx} className="text-[10px] truncate bg-slate-100 text-slate-600 rounded px-1 py-0.5">
                       {app.time} - {patient?.name.split(' ')[0]}
                    </div>
                 )
            })}
            {dailyApps.length > 2 && (
                <div className="text-[10px] text-slate-400 pl-1">+ {dailyApps.length - 2} mais</div>
            )}
        </div>
      </div>
    );
  }

  const selectedDayApps = getAppointmentsForDate(selectedDate);
  const weekDays = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];

  return (
    <div className="flex flex-col lg:flex-row h-[calc(100vh-8rem)] gap-6">

      {/* Left: Calendar */}
      <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        {/* Calendar Header */}
        <div className="p-4 flex items-center justify-between border-b border-slate-100 bg-slate-50">
           <h2 className="text-lg font-bold text-slate-800 capitalize">
             {currentDate.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}
           </h2>
           <div className="flex space-x-2">
             <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200 text-slate-500 hover:text-slate-800 transition-all"><ChevronLeft size={20}/></button>
             <button onClick={() => changeMonth(1)} className="p-2 hover:bg-white rounded-lg border border-transparent hover:border-slate-200 text-slate-500 hover:text-slate-800 transition-all"><ChevronRight size={20}/></button>
           </div>
        </div>

        {/* Week Days */}
        <div className="grid grid-cols-7 border-b border-slate-100 bg-slate-50">
           {weekDays.map(day => (
             <div key={day} className="py-2 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider">{day}</div>
           ))}
        </div>

        {/* Days Grid */}
        <div className="grid grid-cols-7 flex-1 overflow-y-auto">
           {days}
        </div>
      </div>

      {/* Right: Schedule List */}
      <div className="w-full lg:w-96 bg-white rounded-xl shadow-sm border border-slate-100 flex flex-col">
         <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50 rounded-t-xl">
            <div>
              <h3 className="font-bold text-slate-800">Agenda do Dia</h3>
              <p className="text-sm text-slate-500 capitalize">{selectedDate.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
            </div>
            <button onClick={openNewApptModal} className="bg-teal-600 text-white p-2 rounded-lg hover:bg-teal-700 shadow-sm transition-transform active:scale-95">
               <Plus size={20} />
            </button>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {selectedDayApps.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-slate-400">
                  <CalendarIcon size={48} className="mb-3 opacity-20"/>
                  <p className="text-sm">Nenhum agendamento para este dia.</p>
                  <button onClick={openNewApptModal} className="mt-2 text-teal-600 text-sm font-medium hover:underline">Adicionar novo?</button>
               </div>
            ) : (
               selectedDayApps.map(app => {
                 const patient = patients.find(p => p.id === app.patientId);
                 const service = services.find(s => s.id === app.serviceId);
                 return (
                   <div key={app.id} className="bg-white border border-slate-100 rounded-lg p-3 shadow-sm hover:border-teal-200 hover:shadow-md transition-all group relative">
                      <div className="flex justify-between items-start mb-2">
                         <span className="text-lg font-bold text-slate-800 flex items-center">
                            <Clock size={16} className="text-teal-500 mr-1.5"/> {app.time || '00:00'}
                         </span>
                         <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${
                           app.type === AppointmentType.CONSULTA ? 'bg-blue-50 text-blue-600' :
                           app.type === AppointmentType.AVALIACAO ? 'bg-purple-50 text-purple-600' :
                           'bg-orange-50 text-orange-600'
                         }`}>{app.type}</span>
                      </div>
                      <div className="flex items-center space-x-2 mb-1">
                         <User size={14} className="text-slate-400"/>
                         <span className="font-medium text-slate-700">{patient?.name || 'Paciente Removido'}</span>
                      </div>
                      {service && (
                        <div className="text-xs text-slate-500 ml-6 bg-slate-50 inline-block px-1.5 py-0.5 rounded">
                          {service.name}
                        </div>
                      )}
                      {app.notes && (
                        <p className="text-xs text-slate-400 mt-2 italic border-t border-slate-50 pt-2 line-clamp-2">"{app.notes}"</p>
                      )}
                      <div className="absolute right-3 bottom-3 opacity-0 group-hover:opacity-100 transition-opacity">
                         <ChevronRight size={16} className="text-slate-300"/>
                      </div>
                   </div>
                 );
               })
            )}
         </div>
      </div>

      {/* New Appointment Modal (Simplified version for Agenda) */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-xl shadow-2xl max-w-lg w-full overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-lg font-bold text-slate-800 flex items-center">
                  <Plus size={18} className="mr-2 text-teal-600"/> 
                  Novo Agendamento
              </h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors bg-white p-1 rounded-full border border-slate-200 hover:bg-slate-100"><X size={20}/></button>
            </div>

            <div className="p-6 overflow-y-auto">
              <form onSubmit={handleCreateAppointment} className="space-y-5">

                {/* Patient Select (Crucial for Agenda view) */}
                <div>
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Paciente</label>
                   <div className="relative">
                      <select 
                        required
                        value={newApptPatientId} 
                        onChange={e => setNewApptPatientId(e.target.value)} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                      >
                        <option value="">Selecione o paciente...</option>
                        {patients.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                      <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                      </div>
                   </div>
                   {patients.length === 0 && <p className="text-xs text-red-500 mt-1">Cadastre um paciente primeiro na aba Pacientes.</p>}
                </div>

                <div className="grid grid-cols-2 gap-5">
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Data</label>
                     <input disabled type="date" value={selectedDate.toISOString().split('T')[0]} className="w-full border border-slate-200 bg-slate-50 p-2.5 rounded-lg text-slate-500" />
                   </div>
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Horário</label>
                     <input required type="time" value={newApptTime} onChange={e => setNewApptTime(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                   </div>
                </div>

                <div>
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Serviço (Opcional)</label>
                   <div className="relative">
                     <select 
                        value={newApptServiceId} 
                        onChange={(e) => {
                            const sId = e.target.value;
                            setNewApptServiceId(sId);
                            const s = services.find(srv => srv.id === sId);
                            if(s) setNewApptPrice(s.price.toString());
                        }} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                     >
                       <option value="">Selecione...</option>
                       {services.map(s => <option key={s.id} value={s.id}>{s.name} - R$ {s.price.toFixed(2)}</option>)}
                     </select>
                     <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                     </div>
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Tipo</label>
                    <div className="relative">
                        <select 
                        value={newApptType} 
                        onChange={e => setNewApptType(e.target.value as AppointmentType)} 
                        className="w-full border border-slate-300 p-2.5 pr-8 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white appearance-none text-slate-700"
                        >
                        {Object.values(AppointmentType).map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                        <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                        <ChevronDown size={16} />
                        </div>
                    </div>
                  </div>
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Valor (R$)</label>
                     <input required type="number" placeholder="0.00" value={newApptPrice} onChange={e => setNewApptPrice(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Peso (kg)</label>
                     <input type="number" step="0.1" placeholder="0.0" value={newApptWeight} onChange={e => setNewApptWeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                   </div>
                   <div>
                     <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Altura (cm)</label>
                     <input type="number" placeholder="0" value={newApptHeight} onChange={e => setNewApptHeight(e.target.value)} className="w-full border border-slate-300 p-2.5 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none bg-white text-slate-700" />
                   </div>
                </div>

                <div>
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-1 block">Observações</label>
                   <textarea rows={3} placeholder="Detalhes opcionais..." value={newApptNotes} onChange={e => setNewApptNotes(e.target.value)} className="w-full border border-slate-300 p-3 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none bg-white text-slate-700"></textarea>
                </div>

                <button type="submit" className="w-full bg-teal-600 text-white py-3.5 rounded-lg font-bold hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 flex justify-center items-center">
                  <CheckCircle size={20} className="mr-2" /> Agendar
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Agenda;

import React from 'react';
import { MemoryRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Patients from './pages/Patients';
import Financials from './pages/Financials';
